import React, { useState, useMemo, useRef, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); // 0: Open, 1: Half, 2: Closed
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    // Sequence: Open(0) -> Half(1) -> Closed(2) -> Half(1) -> Open(0)
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000;
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      {/* Light effect behind */}
      <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>

      {/* Sprite Container */}
      <div className="relative h-[80dvh] md:h-[100dvh] w-auto flex justify-center overflow-hidden">
        <div 
          className="h-full w-auto transition-transform duration-75 ease-linear"
          style={{
            aspectRatio: '1/1', // Assuming frames are square, adjust if needed
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 40px rgba(0,0,0,0.8))'
          }}
        />
      </div>

      {/* Floor Shadow */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-64 h-8 bg-black/60 blur-2xl rounded-full -z-10"></div>
    </div>
  );
};

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const handleTalk = () => {
    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    if (state.tutorialStep === 'PAY_NOW') {
        actions.setTutorialStep(null);
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    actions.showToast("Purchase complete!");
  };

  const setMultiplier = (itemId: string, mult: number) => {
    setItemMultipliers(prev => ({ ...prev, [itemId]: mult }));
  };

  const toggleCart = () => {
    if (!isCartOpen && state.tutorialStep === 'OPEN_SHOPPING_CART') {
        actions.setTutorialStep('CLOSE_SHOPPING_CART');
    } 
    else if (isCartOpen && state.tutorialStep === 'CLOSE_SHOPPING_CART') {
        actions.setTutorialStep('PAY_NOW');
    }
    setIsCartOpen(!isCartOpen);
  };

  // --- RENDERING ---

  if (viewMode === 'INTERACTION') {
    return (
      <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background */}
        <div className="absolute inset-0 z-0">
          <img 
            src={getAssetUrl('market_bg.jpeg')} 
            alt="Marketplace" 
            className="absolute top-0 opacity-40 w-full h-full object-cover"
            onError={(e) => {
              e.currentTarget.style.display = 'none';
              e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
            }}
          />
          <div className="absolute inset-0 bg-gradient-to-t from-stone-950 via-transparent to-black/20"></div>
        </div>

        {/* Garrick Placement */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
          <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-1000 ease-out">
            <GarrickSprite />
          </div>
        </div>

        {/* Counter Overlay (Conceptual) */}
        <div className="absolute bottom-0 w-full h-[30dvh] z-20 pointer-events-none bg-gradient-to-t from-black/80 to-transparent"></div>

        {/* UI Overlay */}
        <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-none">

          <div className="flex justify-end w-full mb-4 gap-3 pointer-events-auto">
             <button 
                onClick={handleTalk}
                className="flex items-center gap-2 px-6 py-3 bg-stone-900/80 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl group"
              >
                <MessageSquare className="w-4 h-4 text-amber-500" />
                <span className="font-black text-[10px] md:text-sm text-stone-200 uppercase tracking-widest">Talk</span>
              </button>

              <button 
                onClick={() => setViewMode('CATALOG')}
                className="flex items-center gap-2 px-8 py-3 bg-amber-700/80 hover:bg-amber-600 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl group"
              >
                <ShoppingBag className="w-4 h-4 text-white" />
                <span className="font-black text-[10px] md:text-sm text-white uppercase tracking-widest">Browse Goods</span>
              </button>
          </div>

          <DialogueBox 
            speaker="Garrick"
            text={dialogue}
            className="w-full relative pointer-events-auto"
          />
        </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex bg-stone-950 relative overflow-hidden animate-in fade-in duration-500">
      <div className="flex flex-col h-full w-full relative shrink-0">
        <div className="bg-stone-900/80 backdrop-blur-md p-3 md:p-5 border-b border-stone-800 flex items-center justify-between z-10 shrink-0">
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={() => setViewMode('INTERACTION')}
              className="bg-stone-800 hover:bg-stone-700 p-1.5 md:p-2.5 rounded-xl border border-stone-700 transition-colors"
              title="Back to Garrick"
            >
              <ArrowLeft className="w-4 h-4 md:w-5 md:h-5 text-stone-400" />
            </button>
            <div>
              <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif tracking-tight uppercase leading-none">
                Garrick's Wares
              </h2>
              <span className="text-[7px] md:text-[9px] font-mono font-bold text-amber-600 block mt-1 uppercase">
                Tier {currentTier} Supplies Available
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={handleBuy}
              data-tutorial-id="PAY_NOW_BUTTON"
              className={`relative flex items-center gap-2 md:gap-3 px-3 md:px-6 py-1.5 md:py-3 rounded-xl border transition-all shadow-lg active:scale-95 group ${
                cartItemCount === 0
                  ? 'bg-stone-800/40 border-stone-700 text-stone-600 grayscale'
                  : totalCost > state.stats.gold
                    ? 'bg-red-900/40 border-red-700 text-red-300'
                    : 'bg-amber-600 hover:bg-amber-500 border-amber-400 text-white shadow-[0_0_20px_rgba(217,119,6,0.2)]'
              }`}
            >
              <div className="relative">
                <ShoppingCart className={`w-3.5 h-3.5 md:w-5 md:h-5 ${cartItemCount > 0 ? 'animate-bounce' : ''}`} />
                {cartItemCount > 0 && (
                  <div className="absolute -top-2 -right-2 bg-red-600 text-white text-[7px] md:text-[9px] font-black px-1 rounded-full border border-stone-900 ring-1 ring-white/20">
                    {cartItemCount}
                  </div>
                )}
              </div>
              <div className="flex flex-col items-start leading-none">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Pay Now</span>
                <div className="flex items-center gap-0.5 mt-0.5">
                  <span className="text-[9px] md:text-sm font-mono font-black">{totalCost}</span>
                  <Coins className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-200" />
                </div>
              </div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 md:p-6 custom-scrollbar pb-24">
          <div className="grid gap-1.5 md:gap-4 max-w-7xl mx-auto content-start grid-cols-4 xs:grid-cols-5 sm:grid-cols-6 lg:grid-cols-8">
            {MARKET_CATALOG.map(marketItem => {
              const isKeyItem = marketItem.id === 'furnace' || marketItem.id === 'workbench';
              const isScrollItem = marketItem.id.startsWith('scroll_');
              const isOwned =
                (marketItem.id === 'furnace' && state.forge.hasFurnace) ||
                (marketItem.id === 'workbench' && state.forge.hasWorkbench);

              if (isKeyItem && isOwned) return null;

              let itemName = '';
              let itemTier = 1;
              if (marketItem.id === 'furnace') {
                itemName = 'Furnace';
                itemTier = 0;
              } else if (marketItem.id === 'workbench') {
                itemName = 'Workbench';
                itemTier = 1;
              } else if (marketItem.id === 'scroll_t2') {
                itemName = 'Scroll T2';
                itemTier = 1;
                if (currentTier >= 2) return null;
              } else if (marketItem.id === 'scroll_t3') {
                itemName = 'Scroll T3';
                itemTier = 2;
                if (currentTier >= 3) return null;
              } else {
                const itemDef = Object.values(MATERIALS).find(i => i.id === marketItem.id);
                if (!itemDef) return null;
                itemName = (itemDef as any).name;
                itemTier = (itemDef as any).tier || 1;
              }

              if (itemTier > currentTier) return null;

              const stockLeft = (state.marketStock[marketItem.id] || 0) - (cart[marketItem.id] || 0);
              const isSoldOut = stockLeft <= 0;
              const selectedMult = itemMultipliers[marketItem.id] || 1;
              const invCount = state.inventory.find(i => i.id === marketItem.id)?.quantity || 0;

              return (
                <div
                  key={marketItem.id}
                  data-tutorial-id={marketItem.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                  className={`group relative flex flex-col items-center p-1 md:p-2 rounded-lg md:rounded-xl border transition-all h-[140px] md:h-[220px] justify-between overflow-hidden shadow-sm select-none ${
                    pressingItemId === marketItem.id
                      ? 'scale-[0.97] border-amber-500 bg-amber-900/10'
                      : isSoldOut
                        ? 'bg-stone-900 border-stone-800 opacity-60 grayscale'
                        : 'bg-stone-850 border-stone-800'
                  }`}
                >
                  {invCount > 0 && (
                    <div className="absolute top-0.5 left-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-0.5">
                      <Package className="w-1.5 h-1.5 md:w-2 md:h-2" />
                      <span>{invCount}</span>
                    </div>
                  )}

                  <div
                    className={`absolute top-0.5 right-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 ${
                      stockLeft > 0 ? 'bg-emerald-950/60 border-emerald-500/40 text-emerald-400' : 'bg-red-950/60 border-red-500/40 text-red-500'
                    }`}
                  >
                    {isSoldOut ? 'X' : stockLeft}
                  </div>

                  <div
                    className={`flex-1 w-full flex items-center justify-center transition-all relative mt-1 overflow-hidden rounded-lg
                      ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 group-hover:scale-105 active:scale-95'}
                      touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <img
                      src={getAssetUrl(`${marketItem.id}.png`)}
                      className="w-12 h-12 md:w-24 md:h-24 object-contain drop-shadow-md pointer-events-none"
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
                      }}
                      draggable={false}
                    />
                    <div className="hidden text-base md:text-3xl pointer-events-none">📦</div>
                  </div>

                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
                      className="multiplier-btn flex items-center gap-0.5 md:gap-1 my-1 bg-stone-950/80 p-0.5 rounded-lg border border-stone-800/50 z-20"
                    >
                      {[1, 5, 10].map(m => (
                        <button
                          key={m}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            setMultiplier(marketItem.id, m);
                          }}
                          className={`w-4 h-4 md:w-7 md:h-7 rounded text-[6px] md:text-[9px] font-black transition-all ${
                            selectedMult === m
                              ? 'bg-amber-600 text-white shadow-glow-sm'
                              : 'bg-stone-800 text-stone-500 hover:text-stone-300'
                          }`}
                        >
                          x{m}
                        </button>
                      ))}
                    </div>
                  )}

                  <div className="w-full text-center mb-0.5">
                    <h4
                      className={`text-[7px] md:text-[11px] font-black leading-none truncate px-1 ${
                        isKeyItem || isScrollItem ? 'text-amber-400' : 'text-stone-400'
                      }`}
                    >
                      {itemName}
                    </h4>
                  </div>

                  <div
                    className={`w-full py-0.5 md:py-1 rounded-b-lg border-t flex items-center justify-center gap-0.5 font-mono font-black transition-all
                      text-[7px] md:text-xs
                      ${isSoldOut
                        ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed'
                        : 'bg-stone-950 border-stone-800 text-amber-500 cursor-pointer hover:bg-amber-900/20 active:bg-amber-900/40'
                      }
                      select-none touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <span className="hidden md:inline pointer-events-none">
                      <Coins className="w-2.5 h-2.5" />
                    </span>
                    <span className="pointer-events-none">{marketItem.price}</span>
                  </div>

                  {isSoldOut && (
                    <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60 backdrop-blur-[0.5px]">
                      <span className="bg-red-600 text-white text-[6px] md:text-[8px] font-black px-1.5 py-0.5 rounded rotate-12 shadow-md">
                        SOLD
                      </span>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <div
        className={`absolute top-0 right-0 h-full bg-stone-900/95 backdrop-blur-3xl border-l border-stone-800 shadow-[-10px_0_30px_rgba(0,0,0,0.5)] z-[100] flex flex-col transition-all duration-500 ease-in-out ${
          isCartOpen ? 'w-[85%] sm:w-[50%] md:w-80 translate-x-0' : 'w-0 translate-x-full border-none'
        }`}
      >
        <button
          onClick={toggleCart}
          data-tutorial-id="CART_TOGGLE"
          className={`absolute top-1/2 -left-6 md:-left-8 w-6 md:w-8 h-20 md:h-24 -translate-y-1/2 border-y border-l transition-all z-[110] cursor-pointer shadow-xl rounded-l-lg flex flex-col items-center justify-center 
            ${
              cartItemCount > 0
                ? 'bg-amber-600 border-amber-400 animate-pulse text-white shadow-[0_0_20px_rgba(217,119,6,0.3)]'
                : 'bg-stone-800 border-stone-600 text-stone-400 hover:bg-stone-700 hover:text-amber-400'
            }`}
        >
          <ShoppingCart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          {isCartOpen ? (
            <ChevronRight className="w-3 h-3 md:w-4 md:h-4 mt-1 opacity-50" />
          ) : (
            <ChevronLeft
              className={`w-3 h-3 md:w-4 md:h-4 mt-1 ${
                cartItemCount > 0 ? 'text-white' : 'text-amber-500 animate-pulse'
              }`}
            />
          )}
        </button>

        <div className={`flex flex-col h-full w-full ${isCartOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
          <div className="bg-stone-850 p-3 md:p-4 border-b border-stone-800 flex items-center justify-between shrink-0">
            <h3 className="font-serif font-black text-xs md:text-lg text-stone-100 uppercase tracking-tighter truncate">
              Your Cart
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto p-2 md:p-3 space-y-2.5 custom-scrollbar">
            {Object.keys(cart).length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-700 text-center px-4">
                <ShoppingCart className="w-8 h-8 md:w-10 md:h-10 opacity-10 mb-2" />
                <p className="italic font-medium text-[8px] md:text-[10px] uppercase tracking-widest">Cart is empty</p>
              </div>
            ) : (
              Object.entries(cart).map(([id, count]) => {
                const marketItem = MARKET_CATALOG.find(i => i.id === id);
                const name =
                  id === 'furnace'
                    ? 'Furnace'
                    : id === 'workbench'
                      ? 'Workbench'
                      : MATERIALS[id.toUpperCase() as keyof typeof MATERIALS]?.name || id;

                if (!marketItem) return null;

                return (
                  <div key={id} className="flex items-center gap-2 bg-stone-950 p-2 md:p-3 rounded-xl border border-stone-800 group select-none">
                    <div className="w-10 h-10 md:w-14 md:h-14 bg-stone-900 rounded-lg border border-stone-800 flex items-center justify-center shrink-0">
                      <img src={getAssetUrl(`${id}.png`)} className="w-8 h-8 md:w-11 md:h-11 object-contain" draggable={false} />
                    </div>
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                      <div className="text-stone-100 font-bold text-[10px] md:text-sm truncate">{name}</div>
                      <div className="text-amber-600 font-mono text-[9px] md:text-xs font-bold">{marketItem.price * (count as number)} G</div>
                    </div>
                    <div className="flex items-center gap-1.5 shrink-0 bg-stone-900 rounded-lg border border-stone-700 p-0.5">
                      <button
                        type="button"
                        onClick={() => removeFromCart(id)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Minus className="w-2.5 h-2.5" />
                      </button>
                      <span className="min-w-[16px] text-center font-mono text-stone-200 font-bold text-[10px] md:text-xs">{count}</span>
                      <button
                        type="button"
                        onClick={() => addToCart(id, 1)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Plus className="w-2.5 h-2.5" />
                      </button>
                    </div>
                    <button type="button" onClick={() => deleteFromCart(id)} className="p-1 md:p-1.5 hover:text-red-500 transition-colors">
                      <Trash2 className="w-3 h-3 md:w-4 md:h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>

          <div className="bg-stone-850 p-3 md:p-4 border-t border-stone-800 space-y-3 shrink-0">
            <div className="flex justify-between items-center text-[9px] md:text-sm text-stone-600 font-bold uppercase tracking-tighter">
              <span>Grand Total</span>
              <span className={`text-sm md:text-xl font-mono font-black ${totalCost > state.stats.gold ? 'text-red-500' : 'text-amber-500'}`}>
                {totalCost} G
              </span>
            </div>
            <button
              type="button"
              onClick={handleBuy}
              className={`w-full py-2.5 md:py-3 rounded-xl font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 shadow-xl ${
                totalCost > state.stats.gold ? 'bg-stone-800 text-stone-300' : 
                totalCost === 0 ? 'bg-stone-800 text-stone-500 grayscale opacity-60' :
                'bg-amber-600 hover:bg-amber-500 text-white'
              }`}
            >
              <ShoppingBag className="w-4 h-4" />
              <span>{totalCost > state.stats.gold ? 'Insufficient Funds' : 'Purchase'}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MarketTab;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

/**
 * GarrickSprite: 3프레임 스프라이트 시트를 이용한 눈 깜빡임 애니메이션 컴포넌트
 * 프레임 순서: F1(Open) -> F2(Half) -> F3(Closed) -> F2(Half) -> F1(Open)
 */
const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); // 0: Open, 1: Half, 2: Closed
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    // Sequence: 0 -> 1 -> 2 -> 1 -> 0
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000; // 3~7초 사이 랜덤
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      {/* 캐릭터 뒤 광원 효과 */}
      <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-80 h-80 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>

      {/* Garrick Sprite Container */}
      <div className="relative h-[85dvh] md:h-[110dvh] w-auto flex justify-center overflow-hidden bottom-[-5dvh] md:bottom-[-10dvh]">
        <div 
          className="h-full w-auto transition-transform duration-75 ease-linear"
          style={{
            aspectRatio: '1/1', 
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 50px rgba(0,0,0,0.9))'
          }}
        />
      </div>

      {/* 바닥 그림자 */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-80 h-12 bg-black/60 blur-3xl rounded-full -z-10"></div>
    </div>
  );
};

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const handleTalk = () => {
    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    if (state.tutorialStep === 'PAY_NOW') {
        actions.setTutorialStep(null);
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    actions.showToast("Purchase complete!");
  };

  const setMultiplier = (itemId: string, mult: number) => {
    setItemMultipliers(prev => ({ ...prev, [itemId]: mult }));
  };

  const toggleCart = () => {
    if (!isCartOpen && state.tutorialStep === 'OPEN_SHOPPING_CART') {
        actions.setTutorialStep('CLOSE_SHOPPING_CART');
    } 
    else if (isCartOpen && state.tutorialStep === 'CLOSE_SHOPPING_CART') {
        actions.setTutorialStep('PAY_NOW');
    }
    setIsCartOpen(!isCartOpen);
  };

  // --- RENDERING ---

  if (viewMode === 'INTERACTION') {
    return (
      <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background */}
        <div className="absolute inset-0 z-0">
          <img 
            src={getAssetUrl('garricks_store_bg.png')} 
            alt="Garrick's Store" 
            className="absolute top-0 opacity-60 w-full h-full object-cover"
            onError={(e) => {
              e.currentTarget.style.display = 'none';
              e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
            }}
          />
          <div className="absolute inset-0 bg-gradient-to-t from-stone-950 via-transparent to-black/30"></div>
        </div>

        {/* Garrick Placement */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
          <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-1000 ease-out">
            <GarrickSprite />
          </div>
        </div>

        {/* Counter Overlay (Conceptual Bottom Shadow) */}
        <div className="absolute bottom-0 w-full h-[25dvh] z-20 pointer-events-none bg-gradient-to-t from-black/90 to-transparent"></div>

        {/* Interaction HUD */}
        <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-none gap-4">

          <div className="flex justify-end w-full gap-3 pointer-events-auto pr-4">
             <button 
                onClick={handleTalk}
                className="flex items-center gap-2 px-6 py-2.5 md:py-3.5 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-2xl group active:scale-95"
              >
                <MessageSquare className="w-4 h-4 text-amber-500" />
                <span className="font-black text-[9px] md:text-sm text-stone-200 uppercase tracking-widest">Talk</span>
              </button>

              <button 
                onClick={() => setViewMode('CATALOG')}
                className="flex items-center gap-2 px-8 py-2.5 md:py-3.5 bg-amber-700/90 hover:bg-amber-600 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-2xl group active:scale-95"
              >
                <ShoppingBag className="w-4 h-4 text-white" />
                <span className="font-black text-[9px] md:text-sm text-white uppercase tracking-widest">Browse Goods</span>
              </button>
          </div>

          <DialogueBox 
            speaker="Garrick"
            text={dialogue}
            className="w-full relative pointer-events-auto"
          />
        </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex bg-stone-950 relative overflow-hidden animate-in fade-in slide-in-from-right-4 duration-500">
      <div className="flex flex-col h-full w-full relative shrink-0">
        <div className="bg-stone-900/90 backdrop-blur-md p-3 md:p-5 border-b border-stone-800 flex items-center justify-between z-10 shrink-0 shadow-lg">
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={() => setViewMode('INTERACTION')}
              className="bg-stone-800 hover:bg-stone-700 p-2 md:p-3 rounded-xl border border-stone-700 transition-all active:scale-90"
              title="Back to Garrick"
            >
              <ArrowLeft className="w-4 h-4 md:w-5 md:h-5 text-stone-300" />
            </button>
            <div>
              <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif tracking-tight uppercase leading-none">
                Garrick's Wares
              </h2>
              <span className="text-[7px] md:text-[10px] font-mono font-bold text-amber-600 block mt-1 uppercase tracking-wider">
                Tier {currentTier} Supplies Available
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={handleBuy}
              data-tutorial-id="PAY_NOW_BUTTON"
              className={`relative flex items-center gap-2 md:gap-3 px-3 md:px-6 py-1.5 md:py-3 rounded-xl border transition-all shadow-lg active:scale-95 group ${
                cartItemCount === 0
                  ? 'bg-stone-800/40 border-stone-700 text-stone-600 grayscale'
                  : totalCost > state.stats.gold
                    ? 'bg-red-900/40 border-red-700 text-red-300'
                    : 'bg-amber-600 hover:bg-amber-500 border-amber-400 text-white shadow-[0_0_20px_rgba(217,119,6,0.2)]'
              }`}
            >
              <div className="relative">
                <ShoppingCart className={`w-3.5 h-3.5 md:w-5 md:h-5 ${cartItemCount > 0 ? 'animate-bounce' : ''}`} />
                {cartItemCount > 0 && (
                  <div className="absolute -top-2 -right-2 bg-red-600 text-white text-[7px] md:text-[9px] font-black px-1 rounded-full border border-stone-900 ring-1 ring-white/20">
                    {cartItemCount}
                  </div>
                )}
              </div>
              <div className="flex flex-col items-start leading-none">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Pay Now</span>
                <div className="flex items-center gap-0.5 mt-0.5">
                  <span className="text-[9px] md:text-sm font-mono font-black">{totalCost}</span>
                  <Coins className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-200" />
                </div>
              </div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 md:p-6 custom-scrollbar pb-24">
          <div className="grid gap-1.5 md:gap-4 max-w-7xl mx-auto content-start grid-cols-4 xs:grid-cols-5 sm:grid-cols-6 lg:grid-cols-8">
            {MARKET_CATALOG.map(marketItem => {
              const isKeyItem = marketItem.id === 'furnace' || marketItem.id === 'workbench';
              const isScrollItem = marketItem.id.startsWith('scroll_');
              const isOwned =
                (marketItem.id === 'furnace' && state.forge.hasFurnace) ||
                (marketItem.id === 'workbench' && state.forge.hasWorkbench);

              if (isKeyItem && isOwned) return null;

              let itemName = '';
              let itemTier = 1;
              if (marketItem.id === 'furnace') {
                itemName = 'Furnace';
                itemTier = 0;
              } else if (marketItem.id === 'workbench') {
                itemName = 'Workbench';
                itemTier = 1;
              } else if (marketItem.id === 'scroll_t2') {
                itemName = 'Scroll T2';
                itemTier = 1;
                if (currentTier >= 2) return null;
              } else if (marketItem.id === 'scroll_t3') {
                itemName = 'Scroll T3';
                itemTier = 2;
                if (currentTier >= 3) return null;
              } else {
                const itemDef = Object.values(MATERIALS).find(i => i.id === marketItem.id);
                if (!itemDef) return null;
                itemName = (itemDef as any).name;
                itemTier = (itemDef as any).tier || 1;
              }

              if (itemTier > currentTier) return null;

              const stockLeft = (state.marketStock[marketItem.id] || 0) - (cart[marketItem.id] || 0);
              const isSoldOut = stockLeft <= 0;
              const selectedMult = itemMultipliers[marketItem.id] || 1;
              const invCount = state.inventory.find(i => i.id === marketItem.id)?.quantity || 0;

              return (
                <div
                  key={marketItem.id}
                  data-tutorial-id={marketItem.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                  className={`group relative flex flex-col items-center p-1 md:p-2 rounded-lg md:rounded-xl border transition-all h-[140px] md:h-[220px] justify-between overflow-hidden shadow-sm select-none ${
                    pressingItemId === marketItem.id
                      ? 'scale-[0.97] border-amber-500 bg-amber-900/10'
                      : isSoldOut
                        ? 'bg-stone-900 border-stone-800 opacity-60 grayscale'
                        : 'bg-stone-850 border-stone-800'
                  }`}
                >
                  {invCount > 0 && (
                    <div className="absolute top-0.5 left-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-0.5">
                      <Package className="w-1.5 h-1.5 md:w-2 md:h-2" />
                      <span>{invCount}</span>
                    </div>
                  )}

                  <div
                    className={`absolute top-0.5 right-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 ${
                      stockLeft > 0 ? 'bg-emerald-950/60 border-emerald-500/40 text-emerald-400' : 'bg-red-950/60 border-red-500/40 text-red-500'
                    }`}
                  >
                    {isSoldOut ? 'X' : stockLeft}
                  </div>

                  <div
                    className={`flex-1 w-full flex items-center justify-center transition-all relative mt-1 overflow-hidden rounded-lg
                      ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 group-hover:scale-105 active:scale-95'}
                      touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <img
                      src={getAssetUrl(`${marketItem.id}.png`)}
                      className="w-12 h-12 md:w-24 md:h-24 object-contain drop-shadow-md pointer-events-none"
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
                      }}
                      draggable={false}
                    />
                    <div className="hidden text-base md:text-3xl pointer-events-none">📦</div>
                  </div>

                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
                      className="multiplier-btn flex items-center gap-0.5 md:gap-1 my-1 bg-stone-950/80 p-0.5 rounded-lg border border-stone-800/50 z-20"
                    >
                      {[1, 5, 10].map(m => (
                        <button
                          key={m}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            setMultiplier(marketItem.id, m);
                          }}
                          className={`w-4 h-4 md:w-7 md:h-7 rounded text-[6px] md:text-[9px] font-black transition-all ${
                            selectedMult === m
                              ? 'bg-amber-600 text-white shadow-glow-sm'
                              : 'bg-stone-800 text-stone-500 hover:text-stone-300'
                          }`}
                        >
                          x{m}
                        </button>
                      ))}
                    </div>
                  )}

                  <div className="w-full text-center mb-0.5">
                    <h4
                      className={`text-[7px] md:text-[11px] font-black leading-none truncate px-1 ${
                        isKeyItem || isScrollItem ? 'text-amber-400' : 'text-stone-400'
                      }`}
                    >
                      {itemName}
                    </h4>
                  </div>

                  <div
                    className={`w-full py-0.5 md:py-1 rounded-b-lg border-t flex items-center justify-center gap-0.5 font-mono font-black transition-all
                      text-[7px] md:text-xs
                      ${isSoldOut
                        ? 'bg-stone-900 border-stone-800 text-stone-700 cursor-not-allowed'
                        : 'bg-stone-950 border-stone-800 text-amber-500 cursor-pointer hover:bg-amber-900/20 active:bg-amber-900/40'
                      }
                      select-none touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <span className="hidden md:inline pointer-events-none">
                      <Coins className="w-2.5 h-2.5" />
                    </span>
                    <span className="pointer-events-none">{marketItem.price}</span>
                  </div>

                  {isSoldOut && (
                    <div className="absolute inset-0 z-30 flex items-center justify-center bg-black/60 backdrop-blur-[0.5px]">
                      <span className="bg-red-600 text-white text-[6px] md:text-[8px] font-black px-1.5 py-0.5 rounded rotate-12 shadow-md">
                        SOLD
                      </span>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Shopping Cart Drawer */}
      <div
        className={`absolute top-0 right-0 h-full bg-stone-900/95 backdrop-blur-3xl border-l border-stone-800 shadow-[-10px_0_30px_rgba(0,0,0,0.5)] z-[100] flex flex-col transition-all duration-500 ease-in-out ${
          isCartOpen ? 'w-[85%] sm:w-[50%] md:w-80 translate-x-0' : 'w-0 translate-x-full border-none'
        }`}
      >
        <button
          onClick={toggleCart}
          data-tutorial-id="CART_TOGGLE"
          className={`absolute top-1/2 -left-6 md:-left-8 w-6 md:w-8 h-20 md:h-24 -translate-y-1/2 border-y border-l transition-all z-[110] cursor-pointer shadow-xl rounded-l-lg flex flex-col items-center justify-center 
            ${
              cartItemCount > 0
                ? 'bg-amber-600 border-amber-400 animate-pulse text-white shadow-[0_0_20px_rgba(217,119,6,0.3)]'
                : 'bg-stone-800 border-stone-600 text-stone-400 hover:bg-stone-700 hover:text-amber-400'
            }`}
        >
          <ShoppingCart className="w-3.5 h-3.5 md:w-5 md:h-5" />
          {isCartOpen ? (
            <ChevronRight className="w-3 h-3 md:w-4 md:h-4 mt-1 opacity-50" />
          ) : (
            <ChevronLeft
              className={`w-3 h-3 md:w-4 md:h-4 mt-1 ${
                cartItemCount > 0 ? 'text-white' : 'text-amber-500 animate-pulse'
              }`}
            />
          )}
        </button>

        <div className={`flex flex-col h-full w-full ${isCartOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
          <div className="bg-stone-850 p-3 md:p-4 border-b border-stone-800 flex items-center justify-between shrink-0">
            <h3 className="font-serif font-black text-xs md:text-lg text-stone-100 uppercase tracking-tighter truncate">
              Your Cart
            </h3>
          </div>

          <div className="flex-1 overflow-y-auto p-2 md:p-3 space-y-2.5 custom-scrollbar">
            {Object.keys(cart).length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-700 text-center px-4">
                <ShoppingCart className="w-8 h-8 md:w-10 md:h-10 opacity-10 mb-2" />
                <p className="italic font-medium text-[8px] md:text-[10px] uppercase tracking-widest">Cart is empty</p>
              </div>
            ) : (
              Object.entries(cart).map(([id, count]) => {
                const marketItem = MARKET_CATALOG.find(i => i.id === id);
                const name =
                  id === 'furnace'
                    ? 'Furnace'
                    : id === 'workbench'
                      ? 'Workbench'
                      : MATERIALS[id.toUpperCase() as keyof typeof MATERIALS]?.name || id;

                if (!marketItem) return null;

                return (
                  <div key={id} className="flex items-center gap-2 bg-stone-950 p-2 md:p-3 rounded-xl border border-stone-800 group select-none">
                    <div className="w-10 h-10 md:w-14 md:h-14 bg-stone-900 rounded-lg border border-stone-800 flex items-center justify-center shrink-0">
                      <img src={getAssetUrl(`${id}.png`)} className="w-8 h-8 md:w-11 md:h-11 object-contain" draggable={false} />
                    </div>
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                      <div className="text-stone-100 font-bold text-[10px] md:text-sm truncate">{name}</div>
                      <div className="text-amber-600 font-mono text-[9px] md:text-xs font-bold">{marketItem.price * (count as number)} G</div>
                    </div>
                    <div className="flex items-center gap-1.5 shrink-0 bg-stone-900 rounded-lg border border-stone-700 p-0.5">
                      <button
                        type="button"
                        onClick={() => removeFromCart(id)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Minus className="w-2.5 h-2.5" />
                      </button>
                      <span className="min-w-[16px] text-center font-mono text-stone-200 font-bold text-[10px] md:text-xs">{count}</span>
                      <button
                        type="button"
                        onClick={() => addToCart(id, 1)}
                        className="w-5 h-5 md:w-7 md:h-7 flex items-center justify-center bg-stone-800 hover:bg-stone-700 text-stone-400 rounded transition-all"
                      >
                        <Plus className="w-2.5 h-2.5" />
                      </button>
                    </div>
                    <button type="button" onClick={() => deleteFromCart(id)} className="p-1 md:p-1.5 hover:text-red-500 transition-colors">
                      <Trash2 className="w-3 h-3 md:w-4 md:h-4" />
                    </button>
                  </div>
                );
              })
            )}
          </div>

          <div className="bg-stone-850 p-3 md:p-4 border-t border-stone-800 space-y-3 shrink-0">
            <div className="flex justify-between items-center text-[9px] md:text-sm text-stone-600 font-bold uppercase tracking-tighter">
              <span>Grand Total</span>
              <span className={`text-sm md:text-xl font-mono font-black ${totalCost > state.stats.gold ? 'text-red-500' : 'text-amber-500'}`}>
                {totalCost} G
              </span>
            </div>
            <button
              type="button"
              onClick={handleBuy}
              className={`w-full py-2.5 md:py-3 rounded-xl font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 shadow-xl ${
                totalCost > state.stats.gold ? 'bg-stone-800 text-stone-300' : 
                totalCost === 0 ? 'bg-stone-800 text-stone-500 grayscale opacity-60' :
                'bg-amber-600 hover:bg-amber-500 text-white'
              }`}
            >
              <ShoppingBag className="w-4 h-4" />
              <span>{totalCost > state.stats.gold ? 'Insufficient Funds' : 'Purchase'}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MarketTab;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number | string;
}

export default class SmithingScene extends Phaser.Scene {
  /* Fix: Uncommented standard Phaser properties to resolve 'does not exist' errors */
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public events!: Phaser.Events.EventEmitter;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public anims!: Phaser.Animations.AnimationManager;

  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;

  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;

  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private qualityText!: Phaser.GameObjects.Text;

  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private billetContainer!: Phaser.GameObjects.Container;
  private billetImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX = 0;
  private centerY = 0;
  private hitX = 0;
  private hitY = 0;

  private viewW = 0;
  private viewH = 0;

  private anvilConfig = {
    heightRatio: 0.4,
    yOffset: 20,
    imageOffsetY: 20,
    hitAreaOffset: 45,
  };

  private score = 0;
  private targetScore = 100;
  private combo = 0;
  private lastHitTime = 0;
  private hitCooldown = 200;
  private isFinished = false;
  private isPlaying = false;
  private isReadyToStart = false;

  private currentQuality = 100;
  private perfectCount = 0;

  private temperature = 0;
  private coolingRate = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number | string = 0;

  private startRadius = 180;
  private targetRadius = 45;
  private currentRadius = 180;
  private shrinkDuration = 2000;
  private ringTimer = 0;

  // Ring types state
  private currentTargetColor = 0xfabf24;
  private currentSpeedMult = 1.0;

  private readonly UI_PAD_TOP = 18;
  private readonly UI_PAD_SIDE = 12; 
  private readonly UI_PAD_BOTTOM = 24;
  private readonly UI_GAP = 14;

  private readonly TEMP_GAUGE_H_MIN = 110;

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;

  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;

  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping = false;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  private root!: Phaser.GameObjects.Container;

  private isPortrait = false;
  private lastPortrait?: boolean;
  private isRelayouting = false;

  private readonly BILLET_W_ON_ANVIL = 0.80; 
  private readonly BILLET_ANGLE_DEG = -12;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('billet_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), { frameWidth: 298, frameHeight: 188 });
  }

  create() {
    if (this.scale.width <= 0 || this.scale.height <= 0) return;
    this.root = this.add.container(0, 0);
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map((i) => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }
    this.backgroundTile = this.add.tileSprite(0, 0, 1280, 720, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.root.add(this.backgroundTile);
    this.bgOverlay = this.add.rectangle(0, 0, 1280, 720, 0x000000, 0.4).setOrigin(0).setDepth(-1);
    this.root.add(this.bgOverlay);
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.root.add(this.anvilImage);
    this.billetContainer = this.add.container(0, 0).setDepth(3).setAngle(this.BILLET_ANGLE_DEG);
    if (this.textures.exists('billet_stage_0')) {
      this.billetImage = this.add.image(0, 0, 'billet_stage_0').setOrigin(0.5);
      this.billetContainer.add(this.billetImage);
    }
    this.root.add(this.billetContainer);
    this.hammerHitArea = this.add.rectangle(0, 0, 1, 1, 0x00ff00).setDepth(3).setAlpha(0).setAngle(this.BILLET_ANGLE_DEG);
    this.root.add(this.hammerHitArea);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);
    this.root.add([this.targetRing, this.approachRing]);
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.root.add(this.uiContainer);
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.root.add(this.ambientGlow);
    this.flashOverlay = this.add.rectangle(0, 0, 1280, 720, 0xffaa00, 0).setOrigin(0).setDepth(100);
    this.root.add(this.flashOverlay);
    this.setupUI();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);
    this.events.once(Phaser.Scenes.Events.SHUTDOWN, () => {
      this.scale.off('resize', this.handleResize, this);
    });
    this.time.delayedCall(80, () => this.handleResize());
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const x = pointer.x; const y = pointer.y;
        if (this.isBellowsClick(objs)) { this.pumpBellows(); return; }
        if (this.isHeatUpClick(objs)) { this.requestHeatUp(); return; }
        if (!this.isPlaying) { this.handleStartTap(x, y); return; }
        if (this.isPointerInHitArea(x, y) || Phaser.Math.Distance.Between(x, y, this.hitX, this.hitY) < this.startRadius * 0.8) {
          this.handleHammerSwing(x, y);
        } else { this.handleMiss(x, y); }
      }, this
    );
  }

  private isBellowsClick(objs: any[]) { return objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c)); }
  private isHeatUpClick(objs: any[]) { return objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some((c) => objs.includes(c)); }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 25, 0.1, 14, 0xeab308).setOrigin(0, 0.5);
    const progBg = this.add.rectangle(0, 25, 250, 18, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg').setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 55, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([progBg, this.progressBar, this.qualityText]);
    this.tempBar = this.add.rectangle(0, 0, 16, 200, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'Grenze', fontSize: '14px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 28, 210, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 22, 200, 0x0c0a09).setName('tempBg'),
      this.tempBar, this.tempValueText,
    ]);
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(1); 
    const pumpTxt = this.add.text(0, 22, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'Grenze', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, pumpTxt]).setInteractive(new Phaser.Geom.Rectangle(-149, -94, 298, 188), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.heatUpBtnContainer = this.add.container(0, 0);
    const r = 35; 
    const btnBg = this.add.circle(0, 0, r, 0x1c1917, 1).setStrokeStyle(3, 0x57534e).setName('btnBg');
    const btnIcon = this.add.text(0, -8, '🔥', { fontSize: '18px' }).setOrigin(0.5).setName('btnIcon');
    const btnLabel = this.add.text(0, 8, 'HEAT', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'Grenze' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '12px', color: '#78716c', fontFamily: 'Grenze' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([btnBg, btnIcon, btnLabel, countTxt]).setInteractive(new Phaser.Geom.Circle(0, 0, r), Phaser.Geom.Circle.Contains);
    this.uiContainer.add([this.bellowsContainer, this.heatUpBtnContainer]);
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '36px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(26);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'TOUCH TO START' : 'FORGE IS COLD\nADD FUEL', {
        fontFamily: 'Grenze Gotisch', fontSize: '24px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5,
      }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private placeBilletOnAnvil() {
    if (!this.anvilImage || !this.billetContainer) return;
    const anvilDispW = this.anvilImage.displayWidth; const anvilDispH = this.anvilImage.displayHeight;
    const anvilTopY = this.anvilImage.y - anvilDispH / 2; const billetY = anvilTopY + anvilDispH * 0.25;
    const currentKey = this.billetImage?.texture?.key ?? 'billet_stage_0'; const tex = this.textures.get(currentKey);
    const src = tex?.getSourceImage() as HTMLImageElement | HTMLCanvasElement | undefined;
    const baseTexW = src?.width ?? 1220; const baseTexH = src?.height ?? 300;
    const targetBilletW = anvilDispW * this.BILLET_W_ON_ANVIL; const ratio = targetBilletW / baseTexW;
    const billetScale = Phaser.Math.Clamp(ratio, 0.15, 2.0);
    this.billetContainer.setAngle(this.BILLET_ANGLE_DEG).setScale(billetScale).setPosition(this.anvilImage.x * 1.2, billetY);
    const billetDispW = baseTexW * billetScale; const billetDispH = baseTexH * billetScale;
    this.hammerHitArea.setAngle(this.BILLET_ANGLE_DEG).setSize(billetDispW * 0.6, billetDispH * 1.0);
    const rad = Phaser.Math.DegToRad(this.BILLET_ANGLE_DEG); const hitOffset = this.anvilConfig.hitAreaOffset * billetScale;
    this.hammerHitArea.setPosition(this.billetContainer.x - Math.sin(rad) * hitOffset, this.billetContainer.y + Math.cos(rad) * hitOffset);
    this.rebuildHitPoly();
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.gameSize.width; const h = gameSize?.height ?? this.scale.gameSize.height;
    if (w <= 0 || h <= 0) return;
    const nextPortrait = h > w; this.cameras.main.setViewport(0, 0, w, h);
    if (this.root) { this.root.setRotation(0); this.root.setPosition(0, 0); }
    const apply = (sw: number, sh: number, portrait: boolean) => {
      this.viewW = sw; this.viewH = sh; this.centerX = sw / 2; this.centerY = sh / 2;
      if (this.backgroundTile) this.backgroundTile.setSize(sw, sh);
      if (this.bgOverlay) this.bgOverlay.setSize(sw, sh);
      if (this.flashOverlay) this.flashOverlay.setSize(sw, sh);
      const anvilW = sw * 1.2; const anvilScale = anvilW / this.anvilImage.width;
      const anvilY = portrait ? this.centerY : this.centerY + this.anvilConfig.yOffset;
      const anvilX = portrait ? sw * 0.35 : this.centerX;

      this.anvilImage.setScale(anvilScale).setPosition(anvilX, anvilY + this.anvilConfig.imageOffsetY);
      if (this.ambientGlow) this.ambientGlow.setPosition(anvilX, anvilY);
      this.placeBilletOnAnvil();
      const basis = Math.min(sw, sh); this.startRadius = Phaser.Math.Clamp(basis * (portrait ? 0.28 : 0.35), 105, 240);

      const isCompact = sh < 450; this.repositionUI(sw, sh, portrait, isCompact);
      if (this.isPlaying) this.resetRing();
    };
    if (this.lastPortrait === undefined) { this.lastPortrait = nextPortrait; this.isPortrait = nextPortrait; apply(w, h, nextPortrait); return; }
    const changed = this.lastPortrait !== nextPortrait; this.lastPortrait = nextPortrait; this.isPortrait = nextPortrait;
    if (changed && !this.isRelayouting) {
      this.isRelayouting = true; const cam = this.cameras.main; cam.fadeOut(120, 0, 0, 0);
      this.time.delayedCall(140, () => {
        const ww = this.scale.gameSize.width; const hh = this.scale.gameSize.height; cam.setViewport(0, 0, ww, hh);
        apply(ww, hh, this.isPortrait); cam.fadeIn(120, 0, 0, 0);
        this.time.delayedCall(160, () => (this.isRelayouting = false));
      });
      return;
    }
    apply(w, h, nextPortrait);
  }

  private repositionUI(sw: number, sh: number, portrait: boolean, isCompact: boolean) {
    if (!this.uiContainer) return;
    const padTop = this.UI_PAD_TOP; 
    const padBottom = this.UI_PAD_BOTTOM; const gap = this.UI_GAP;

    // Adjusted to 18% width area for the controllers
    const sideAreaWidth = Math.min(sw, sh) * 0.18;
    const rightX = sw - (sideAreaWidth / 2) - this.UI_PAD_SIDE;

    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    const progWidth = Math.min(sw * (portrait ? 0.72 : 0.6), 340);
    const progX = this.centerX - progWidth / 2;
    progBg.setPosition(progX, padTop + 10).setSize(progWidth, 18);
    this.progressBar.setPosition(progX, padTop + 10);
    this.updateProgressBar();
    this.qualityText.setPosition(this.centerX, padTop + 40).setFontSize(isCompact ? '16px' : '18px');

    const bellowsScale = sideAreaWidth / 298;
    this.bellowsContainer.setScale(bellowsScale);
    const heatScale = sideAreaWidth / 70;
    this.heatUpBtnContainer.setScale(heatScale);

    const bellowsH = 188 * bellowsScale;
    const heatUpH = 70 * heatScale;
    const heatUpY = sh - padBottom - (heatUpH / 2);
    const bellowsY = heatUpY - (heatUpH / 2) - gap - (bellowsH / 2);

    this.heatUpBtnContainer.setPosition(rightX, heatUpY); 
    this.bellowsContainer.setPosition(rightX, bellowsY);

    const tFrame = this.uiContainer.getByName('tempFrame') as Phaser.GameObjects.Rectangle;
    const tBg = this.uiContainer.getByName('tempBg') as Phaser.GameObjects.Rectangle;
    const gaugeTop = padTop + 70; const gaugeBottomLimit = bellowsY - (bellowsH / 2) - gap;
    const availableH = Math.max(0, gaugeBottomLimit - gaugeTop);
    let gaugeH = Math.min(availableH, sh * 0.6);
    if (availableH >= this.TEMP_GAUGE_H_MIN) { gaugeH = Math.max(gaugeH, this.TEMP_GAUGE_H_MIN); } else { gaugeH = availableH; }
    const gaugeCenterY = gaugeTop + gaugeH / 2;

    tFrame.setPosition(rightX, gaugeCenterY).setSize(28, gaugeH + 10);
    tBg.setPosition(rightX, gaugeCenterY).setSize(22, gaugeH);
    this.tempBar.setSize(16, gaugeH); this.tempBar.setPosition(rightX, gaugeCenterY + gaugeH / 2);
    this.tempValueText.setPosition(rightX, gaugeCenterY - gaugeH / 2 - 16).setFontSize(isCompact ? '12px' : '14px');

    const infoY = portrait ? sh * 0.3 : this.centerY - (isCompact ? 80 : 140);
    this.infoText.setPosition(this.centerX, infoY).setFontSize(portrait ? (isCompact ? '20px' : '24px') : (isCompact ? '20px' : '26px'));
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const cx = this.hammerHitArea.x; const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad); const sin = Math.sin(rad);
    const corners = [ { x: -w / 2, y: -h / 2 }, { x: w / 2, y: -h / 2 }, { x: w / 2, y: h / 2 }, { x: -w / 2, y: h / 2 }, ].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) { return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py); }

  private handleStartTap(x: number, y: number) {
    if (this.isReadyToStart) {
      this.isPlaying = true; this.infoText.setVisible(false); this.resetRing();
      this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
    } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, x, y); }
  }

  private handleHammerSwing(x: number, y: number) {
    if (this.isFinished) return; if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0, x, y); return; }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < this.targetRadius * 0.35) {
      this.score += Math.ceil(8 * eff); this.combo++; this.perfectCount++;
      if (this.perfectCount >= 6) { this.currentQuality += 1; }
      this.createSparks(30, this.currentTargetColor, 1.5, 'spark_perfect', x, y); this.showFeedback('PERFECT!', 0xffb300, 1.4, this.hitX, this.hitY); this.cameras.main.shake(150, 0.02);
    } else if (diff < this.targetRadius * 0.95) {
      this.score += Math.ceil(5 * eff); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(15, 0xffffff, 1.1, 'spark_normal', x, y); this.showFeedback('GOOD', 0xe5e5e5, 1.1, this.hitX, this.hitY);
    } else { this.handleMiss(x, y); }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    // Added 1.0 as the scale argument to fix the error: Expected 5 arguments, but got 4.
    this.cameras.main.shake(100, 0.01); this.showFeedback('MISS', 0xef4444, 1.0, x ?? this.hitX, y ?? this.hitY);
    this.updateProgressBar(); this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false; this.infoText.setText('FORGE IS COLD\nADD FUEL').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    const ratio = this.temperature / 100; this.tempBar.scaleY = ratio; this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    let barColor = 0xeab308; if (ratio < 0.4) barColor = 0x3b82f6; else if (ratio > 0.7) barColor = 0xef4444;
    this.tempBar.setFillStyle(barColor);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6)); this.setBilletStage(stage);
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBilletStage(stage: number) {
    const key = `blade_stage_${stage}`; if (stage === 0) { if (this.billetImage) this.billetImage.setTexture('billet_stage_0'); return; }
    if (!this.textures.exists(key)) return;
    if (!this.billetImage) { this.billetImage = this.add.image(0, 0, key).setOrigin(0.5); this.billetContainer.add(this.billetImage); this.placeBilletOnAnvil(); return; }
    if (this.billetImage.texture.key !== key) {
      this.billetImage.setTexture(key); this.placeBilletOnAnvil();
      const sx = this.billetContainer.scaleX; const sy = this.billetContainer.scaleY;
      this.tweens.add({ targets: this.billetContainer, scaleX: sx * 1.08, scaleY: sy * 1.08, duration: 100, yoyo: true, });
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta * this.currentSpeedMult; 
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5); 
    this.currentRadius = this.startRadius * (1 - t * t);

    // Color interpolation: Start at White (0xffffff), target Current Type Color
    const colorT = Math.min(this.ringTimer / this.shrinkDuration, 1.0);
    const targetRGB = Phaser.Display.Color.IntegerToColor(this.currentTargetColor);

    const r = Math.floor(255 + (targetRGB.red - 255) * colorT);
    const g = Math.floor(255 + (targetRGB.green - 255) * colorT);
    const b = Math.floor(255 + (targetRGB.blue - 255) * colorT);
    const ringColor = Phaser.Display.Color.GetColor(r, g, b);

    // Increased alpha values for better visibility
    const ringAlpha = 0.6 + (colorT * 0.3);

    this.approachRing.clear()
      .lineStyle(6, ringColor, ringAlpha)
      .strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));

    if (this.currentRadius < this.targetRadius - 25) { this.combo = 0; this.resetRing(); }
  }

  private resetRing() {
    if (this.temperature <= 0) return; this.targetRing.clear(); this.approachRing.clear(); this.currentRadius = this.startRadius; this.ringTimer = 0;

    // Select speed and color type
    const randType = Math.random();
    if (randType < 0.2) { // SLOW
      this.currentTargetColor = 0x10b981; // Green
      this.currentSpeedMult = 0.75;
    } else if (randType < 0.75) { // NORMAL
      this.currentTargetColor = 0xfabf24; // Amber
      this.currentSpeedMult = 1.0;
    } else { // FAST
      this.currentTargetColor = 0xef4444; // Red
      this.currentSpeedMult = 1.45;
    }

    // Randomized target size: 18% to 32% of start radius
    this.targetRadius = this.startRadius * Phaser.Math.FloatBetween(0.18, 0.32);

    const w = this.hammerHitArea.width; const h = this.hammerHitArea.height;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35); const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));

    if (this.isPlaying) { 
      this.targetRing.clear()
        .fillStyle(this.currentTargetColor, 0.2)
        .fillCircle(this.hitX, this.hitY, this.targetRadius)
        .lineStyle(4, this.currentTargetColor, 0.7)
        .strokeCircle(this.hitX, this.hitY, this.targetRadius); 
    }
  }

  private updateProgressBar() {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    if (!progBg) return; this.progressBar.width = Math.max(0.1, Phaser.Math.Clamp((this.score / this.targetScore) * progBg.width, 0, progBg.width));
  }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'spark_normal', { lifespan: 600, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.6, end: 0 }, gravityY: 1000, blendMode: 'ADD', tint: color, });
    this.root.add(emitter); emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: '32px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 7, }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy(), });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 75).setText(`${this.combo} COMBO!`).setAlpha(1).setScale(1.2); this.tweens.add({ targets: this.comboText, scale: { from: 1.4, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 700, }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(bg); this.tweens.add({ targets: bg, alpha: 0.8, duration: 500 });
    const label = this.getQualityLabel(this.currentQuality);
    const textContent = this.isPortrait ? `${label}\nCRAFT!` : `${label} CRAFT!`;
    const fontSize = this.isPortrait ? `${Math.min(36, this.viewW * 0.08)}px` : '48px';
    const txt = this.add.text(this.centerX, this.centerY, textContent, { fontFamily: 'Grenze Gotisch', fontSize: fontSize, color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 4, align: 'center', }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: this.isPortrait ? 1.0 : 1.1 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); }, });
  }

  private pumpBellows() {
    // Removed isPumping check to allow immediate re-triggering for better responsiveness
    this.isPumping = true; 
    this.bellowsSprite.play('bellows_pump', true); // Force animation restart
    if (this.temperature > 0) { 
        this.temperature = Math.min(100, this.temperature + 5); 
        if (!this.isPlaying && !this.isReadyToStart) { 
            this.isReadyToStart = true; 
            this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); 
        } 
    }
  }

  private requestHeatUp() { 
    const hasCharcoal = this.charcoalCount === '∞' || (typeof this.charcoalCount === 'number' && this.charcoalCount > 0);
    if (hasCharcoal && this.onHeatUpRequest) { 
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true }); 
      this.onHeatUpRequest(); 
    } else { 
      this.cameras.main.shake(100, 0.005); 
    } 
  }

  public heatUp() { this.temperature = Math.min(100, this.temperature + 40); if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('TOUCH TO START').setColor('#fbbf24'); } this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4); this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' }); }
  public updateCharcoalCount(count: number | string) { this.charcoalCount = count; this.refreshHeatUpButton(); }
  private refreshHeatUpButton() { 
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Arc; 
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text; 
    if (countTxt) countTxt.setText(`x${this.charcoalCount}`); 

    const hasCharcoal = this.charcoalCount === '∞' || (typeof this.charcoalCount === 'number' && this.charcoalCount > 0);
    if (bg) bg.setStrokeStyle(3, hasCharcoal ? 0xea580c : 0x292524); 
  }
  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  /* Fix: Uncommented standard Phaser properties to resolve 'does not exist' errors */
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    // 망치 스프라이트 (루트 컨테이너에 추가하여 커서 이동에 독립적으로 애니메이션 가능하게 함)
    this.hammerSprite = this.add.image(0, 0, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0).setDepth(25);
    this.root.add(this.hammerSprite);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i, nodePos.x, nodePos.y);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    // 망치는 타격 시에만 보이게 관리하므로 기본적으로 숨김
    this.hammerSprite.setAlpha(0);

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 망치 타격 애니메이션 (날아와서 때리는 모션, 5도 -> -30도)
      if (!this.isLeatherWork) {
          // 시작 위치: 타겟 위치에서 상단으로 120px 오프셋 (Y축을 더 올림)
          this.hammerSprite
              .setAlpha(1)
              .setPosition(targetX + 40, targetY - 120)
              .setAngle(5);

          this.tweens.add({
              targets: this.hammerSprite,
              x: targetX,
              y: targetY + 20, // 망치 헤드가 못 머리 상단에 닿도록 보정 (앵커인 손잡이 부분을 타겟 중심 아래로 배치하여 헤드가 닿게 함)
              angle: -30,
              duration: 100,
              ease: 'Cubic.in',
              onComplete: () => {
                  // 타격 후 살짝 반동하며 사라짐
                  this.tweens.add({
                      targets: this.hammerSprite,
                      angle: -10,
                      y: targetY + 10,
                      alpha: 0,
                      duration: 250,
                      ease: 'Cubic.out'
                  });
              }
          });
      }

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

/**
 * GarrickSprite: 3프레임 스프라이트 시트를 이용한 눈 깜빡임 애니메이션 컴포넌트
 */
const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); // 0: Open, 1: Half, 2: Closed
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000;
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      {/* 캐릭터 뒤 광원 효과 - 크기 조정 */}
      <div className="absolute bottom-[25%] left-1/2 -translate-x-1/2 w-64 h-64 bg-amber-500/10 blur-[80px] rounded-full -z-10 animate-pulse"></div>

      {/* Garrick Sprite Container - 크기 축소 (85/110 -> 60/75) */}
      <div className="relative h-[60dvh] md:h-[75dvh] w-auto flex justify-center overflow-hidden bottom-[2dvh]">
        <div 
          className="h-full w-auto transition-transform duration-75 ease-linear"
          style={{
            aspectRatio: '1/1', 
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 40px rgba(0,0,0,0.85))'
          }}
        />
      </div>

      {/* 바닥 그림자 - 크기 조정 */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-64 h-8 bg-black/60 blur-3xl rounded-full -z-10"></div>
    </div>
  );
};

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const handleTalk = () => {
    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    if (state.tutorialStep === 'PAY_NOW') {
        actions.setTutorialStep(null);
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    actions.showToast("Purchase complete!");
  };

  const setMultiplier = (itemId: string, mult: number) => {
    setItemMultipliers(prev => ({ ...prev, [itemId]: mult }));
  };

  const toggleCart = () => {
    if (!isCartOpen && state.tutorialStep === 'OPEN_SHOPPING_CART') {
        actions.setTutorialStep('CLOSE_SHOPPING_CART');
    } 
    else if (isCartOpen && state.tutorialStep === 'CLOSE_SHOPPING_CART') {
        actions.setTutorialStep('PAY_NOW');
    }
    setIsCartOpen(!isCartOpen);
  };

  // --- RENDERING ---

  if (viewMode === 'INTERACTION') {
    return (
      <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background */}
        <div className="absolute inset-0 z-0">
          <img 
            src={getAssetUrl('garricks_store_bg.png')} 
            alt="Garrick's Store" 
            className="absolute top-0 opacity-60 w-full h-full object-cover"
            onError={(e) => {
              e.currentTarget.style.display = 'none';
              e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)';
            }}
          />
          <div className="absolute inset-0 bg-gradient-to-t from-stone-950 via-transparent to-black/30"></div>
        </div>

        {/* Garrick Placement */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none pb-0">
          <div className="relative flex justify-center items-end w-full animate-in fade-in zoom-in-95 duration-1000 ease-out">
            <GarrickSprite />
          </div>
        </div>

        {/* Counter Overlay (Conceptual Bottom Shadow) */}
        <div className="absolute bottom-0 w-full h-[25dvh] z-20 pointer-events-none bg-gradient-to-t from-black/90 to-transparent"></div>

        {/* Interaction HUD */}
        <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-none gap-4">

          <div className="flex justify-end w-full gap-3 pointer-events-auto pr-4">
             <button 
                onClick={handleTalk}
                className="flex items-center gap-2 px-6 py-2.5 md:py-3.5 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-2xl group active:scale-95"
              >
                <MessageSquare className="w-4 h-4 text-amber-500" />
                <span className="font-black text-[9px] md:text-sm text-stone-200 uppercase tracking-widest">Talk</span>
              </button>

              <button 
                onClick={() => setViewMode('CATALOG')}
                className="flex items-center gap-2 px-8 py-2.5 md:py-3.5 bg-amber-700/90 hover:bg-amber-600 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-2xl group active:scale-95"
              >
                <ShoppingBag className="w-4 h-4 text-white" />
                <span className="font-black text-[9px] md:text-sm text-white uppercase tracking-widest">Browse Goods</span>
              </button>
          </div>

          <DialogueBox 
            speaker="Garrick"
            text={dialogue}
            className="w-full relative pointer-events-auto"
          />
        </div>
      </div>
    );
  }

  return (
    <div className="h-full w-full flex bg-stone-950 relative overflow-hidden animate-in fade-in slide-in-from-right-4 duration-500">
      <div className="flex flex-col h-full w-full relative shrink-0">
        <div className="bg-stone-900/90 backdrop-blur-md p-3 md:p-5 border-b border-stone-800 flex items-center justify-between z-10 shrink-0 shadow-lg">
          <div className="flex items-center gap-2 md:gap-4">
            <button 
              onClick={() => setViewMode('INTERACTION')}
              className="bg-stone-800 hover:bg-stone-700 p-2 md:p-3 rounded-xl border border-stone-700 transition-all active:scale-90"
              title="Back to Garrick"
            >
              <ArrowLeft className="w-4 h-4 md:w-5 md:h-5 text-stone-300" />
            </button>
            <div>
              <h2 className="text-sm md:text-2xl font-black text-stone-100 font-serif tracking-tight uppercase leading-none">
                Garrick's Wares
              </h2>
              <span className="text-[7px] md:text-[10px] font-mono font-bold text-amber-600 block mt-1 uppercase tracking-wider">
                Tier {currentTier} Supplies Available
              </span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
              onClick={handleBuy}
              data-tutorial-id="PAY_NOW_BUTTON"
              className={`relative flex items-center gap-2 md:gap-3 px-3 md:px-6 py-1.5 md:py-3 rounded-xl border transition-all shadow-lg active:scale-95 group ${
                cartItemCount === 0
                  ? 'bg-stone-800/40 border-stone-700 text-stone-600 grayscale'
                  : totalCost > state.stats.gold
                    ? 'bg-red-900/40 border-red-700 text-red-300'
                    : 'bg-amber-600 hover:bg-amber-500 border-amber-400 text-white shadow-[0_0_20px_rgba(217,119,6,0.2)]'
              }`}
            >
              <div className="relative">
                <ShoppingCart className={`w-3.5 h-3.5 md:w-5 md:h-5 ${cartItemCount > 0 ? 'animate-bounce' : ''}`} />
                {cartItemCount > 0 && (
                  <div className="absolute -top-2 -right-2 bg-red-600 text-white text-[7px] md:text-[9px] font-black px-1 rounded-full border border-stone-900 ring-1 ring-white/20">
                    {cartItemCount}
                  </div>
                )}
              </div>
              <div className="flex flex-col items-start leading-none">
                <span className="text-[8px] md:text-[10px] font-black uppercase tracking-widest">Pay Now</span>
                <div className="flex items-center gap-0.5 mt-0.5">
                  <span className="text-[9px] md:text-sm font-mono font-black">{totalCost}</span>
                  <Coins className="w-2.5 h-2.5 md:w-3 md:h-3 text-amber-200" />
                </div>
              </div>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 md:p-6 custom-scrollbar pb-24">
          <div className="grid gap-1.5 md:gap-4 max-w-7xl mx-auto content-start grid-cols-4 xs:grid-cols-5 sm:grid-cols-6 lg:grid-cols-8">
            {MARKET_CATALOG.map(marketItem => {
              const isKeyItem = marketItem.id === 'furnace' || marketItem.id === 'workbench';
              const isScrollItem = marketItem.id.startsWith('scroll_');
              const isOwned =
                (marketItem.id === 'furnace' && state.forge.hasFurnace) ||
                (marketItem.id === 'workbench' && state.forge.hasWorkbench);

              if (isKeyItem && isOwned) return null;

              let itemName = '';
              let itemTier = 1;
              if (marketItem.id === 'furnace') {
                itemName = 'Furnace';
                itemTier = 0;
              } else if (marketItem.id === 'workbench') {
                itemName = 'Workbench';
                itemTier = 1;
              } else if (marketItem.id === 'scroll_t2') {
                itemName = 'Scroll T2';
                itemTier = 1;
                if (currentTier >= 2) return null;
              } else if (marketItem.id === 'scroll_t3') {
                itemName = 'Scroll T3';
                itemTier = 2;
                if (currentTier >= 3) return null;
              } else {
                const itemDef = Object.values(MATERIALS).find(i => i.id === marketItem.id);
                if (!itemDef) return null;
                itemName = (itemDef as any).name;
                itemTier = (itemDef as any).tier || 1;
              }

              if (itemTier > currentTier) return null;

              const stockLeft = (state.marketStock[marketItem.id] || 0) - (cart[marketItem.id] || 0);
              const isSoldOut = stockLeft <= 0;
              const selectedMult = itemMultipliers[marketItem.id] || 1;
              const invCount = state.inventory.find(i => i.id === marketItem.id)?.quantity || 0;

              return (
                <div
                  key={marketItem.id}
                  data-tutorial-id={marketItem.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                  className={`group relative flex flex-col items-center p-1 md:p-2 rounded-lg md:rounded-xl border transition-all h-[140px] md:h-[220px] justify-between overflow-hidden shadow-sm select-none ${
                    pressingItemId === marketItem.id
                      ? 'scale-[0.97] border-amber-500 bg-amber-900/10'
                      : isSoldOut
                        ? 'bg-stone-900 border-stone-800 opacity-60 grayscale'
                        : 'bg-stone-850 border-stone-800'
                  }`}
                >
                  {invCount > 0 && (
                    <div className="absolute top-0.5 left-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 bg-slate-900/80 border-slate-600 text-slate-300 flex items-center gap-0.5">
                      <Package className="w-1.5 h-1.5 md:w-2 md:h-2" />
                      <span>{invCount}</span>
                    </div>
                  )}

                  <div
                    className={`absolute top-0.5 right-0.5 px-1 py-0 rounded text-[6px] md:text-[8px] font-black uppercase tracking-tighter border z-10 ${
                      stockLeft > 0 ? 'bg-emerald-950/60 border-emerald-500/40 text-emerald-400' : 'bg-red-950/60 border-red-500/40 text-red-500'
                    }`}
                  >
                    {isSoldOut ? 'X' : stockLeft}
                  </div>

                  <div
                    className={`flex-1 w-full flex items-center justify-center transition-all relative mt-1 overflow-hidden rounded-lg
                      ${isSoldOut ? 'cursor-not-allowed' : 'cursor-pointer hover:bg-stone-800/50 group-hover:scale-105 active:scale-95'}
                      touch-none
                    `}
                    onPointerDown={(e) => {
                      if (isSoldOut) return;
                      handleStartLongPress(e, marketItem.id);
                    }}
                    onPointerUp={handleEndLongPress}
                    onPointerLeave={handleEndLongPress}
                    onPointerCancel={handleEndLongPress}
                  >
                    <img
                      src={getAssetUrl(`${marketItem.id}.png`)}
                      className="w-12 h-12 md:w-24 md:h-24 object-contain drop-shadow-md pointer-events-none"
                      onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.nextElementSibling?.classList.remove('hidden');
                      }}
                      draggable={false}
                    />
                    <div className="hidden text-base md:text-3xl pointer-events-none">📦</div>
                  </div>

                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
