                  {!isSoldOut && !isKeyItem && !isScrollItem && (
                    <div
                      className="multiplier-btn flex items-center gap-0.5 md:gap-1 my-1 bg-stone-950/80 p-0.5 rounded-lg border border-stone-800/50 z-20"
                    >
                      {[1, 5, 10].map(m => (
                        <button
                          key={m}
