        className={`absolute top-0 right-0 h-full bg-stone-900/95 backdrop-blur-3xl border-l border-stone-800 shadow-[-10px_0_30px_rgba(0,0,0,0.5)] z-[100] flex flex-col transition-all duration-500 ease-in-out ${
