          <DialogueBox speaker="Lockhart" text="The forge is alive. The shop must follow. Let's head to the Shop tab." options={[{ label: "Continue", action: () => actions.setTutorialStep('OPEN_SHOP_TAB_GUIDE'), variant: 'primary' }]} /></div></div>
