          <div className="fixed inset-0 z-[2500] flex flex-col justify-end items-center bg-black/40 backdrop-blur-sm pb-6 md:pb-12 px-4 pointer-events-none"><div className="w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto">
          <DialogueBox speaker="Lockhart" text="The forge is alive. The shop must follow. Let's head to the Shop tab." options={[{ label: "Continue", action: () => actions.setTutorialStep('OPEN_SHOP_TAB_GUIDE'), variant: 'primary' }]} /></div></div>
