          <DialogueBox speaker="Lockhart" text="The heat is steady... I can feel the ancient rhythm returning. I'll craft a Bronze Shortsword to test the unit." options={[{ label: "Continue", action: () => actions.setTutorialStep('FORGE_TAB_GUIDE'), variant: 'primary' }]} /></div></div>
      )}
      {state.tutorialStep === 'CRAFT_RESULT_PROMPT' && (
          <div className="fixed inset-0 z-[2500] flex flex-col justify-end items-center bg-transparent backdrop-blur-none pb-6 md:pb-12 px-4 pointer-events-none"><div className="w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto">
          <DialogueBox speaker="Lockhart" text="Higher mastery grants permanent bonuses. Let's finish this piece." options={[{ label: "Continue", action: () => actions.setTutorialStep('FINALIZE_FORGE_GUIDE'), variant: 'primary' }]} /></div></div>
      )}
      {state.tutorialStep === 'SHOP_INTRO_PROMPT' && (
          <div className="fixed inset-0 z-[2500] flex flex-col justify-end items-center bg-black/40 backdrop-blur-sm pb-6 md:pb-12 px-4 pointer-events-none"><div className="w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto">
