            )}

            {/* Narrative - Positioned Top-24 and rendered after mask to stay bright */}
            {script && (
                <div className="absolute top-24 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl pointer-events-none z-[2200]">
