              <DialogueBox speaker="Lockhart" text="Higher mastery grants permanent bonuses. Let's finish this piece." options={[{ label: "Continue", action: () => actions.setTutorialStep('FINALIZE_FORGE_GUIDE'), variant: 'primary' }]} />
