    </div>
  );
};

export default MainGameLayout;

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { getAssetUrl } from '../../../utils';
import { TutorialSceneMode } from '../../../types/game-state';
import { Flame, Zap, Pointer, FastForward } from 'lucide-react';
import ConfirmationModal from '../../modals/ConfirmationModal';

type SequenceStep = 
    | 'IDLE' 
    | 'POST_REPLACE_TALK' 
    | 'WAIT_HEAT' 
    | 'HEAT_CONFIRM' 
    | 'WAIT_CONTINUE_BELLOWS' 
    | 'WAIT_PUMP' 
    | 'FINAL_TALK';

type TutorialDirection = 'top' | 'bottom' | 'left' | 'right' | 'topleft' | 'topright' | 'bottomleft' | 'bottomright';

interface SceneStepConfig {
    targetId: string;
    label: string;
    direction: TutorialDirection;
}

const SCRIPTS: Record<string, { text: string; options?: any[] }> = {
    PROLOGUE_0: { text: "I have just returned from the hill after burying my family... My hands, stained with earth, are still trembling." },
    PROLOGUE_1: { text: "The forge has been ruthlessly trampled by their hands. Everything I built... gone in a single night of fire and blood." },
    PROLOGUE_2: { text: "But the fury within me burns hotter than any flame. For the sake of vengeance, I will rekindle the embers of this forge once more." },
    PROLOGUE_3: { text: "Wait... the furnace is completely beyond repair. I cannot melt ore without a steady flame." },
    PROLOGUE_4: { text: "I must head to the Market immediately to find a replacement. The hammer of the Lockhart lineage will not be silenced." },

    FURNACE_0: { text: "The furnace is finally in place. The air in the forge doesn't feel so heavy and cold anymore." },
    FURNACE_1: { text: "It's a sturdy unit. I've managed to seal the connections, but I should check if the flue is drawing correctly." },
    FURNACE_HEAT_PROMPT: { text: "Let's see if the fuel takes. I need to check the ignition systems." },
    FURNACE_HEATED: { text: "The temperature is rising. The heat is building... the chimney is drawing well." },
    FURNACE_COOLING: { text: "The fire is settling down. I should use the bellows to keep the oxygen flowing." },
    FURNACE_BELLOWS_MONO: { text: "If the temperature drops below 400°C, the bellows won't be enough to bring it back to a roar. I must act while the embers are hot." },
    FURNACE_PUMP_PROMPT: { text: "Let's see if we can reach the forging temperature. Pump it to the limit!" },
    FURNACE_MAXED: { text: "Magnificent. The forge is finally alive and roaring. I'm ready to begin the work of retribution." }
};

const SCENE_STEPS_CONFIG: Partial<Record<SequenceStep, SceneStepConfig>> = {
    WAIT_HEAT: { targetId: "tutorial-heat", label: "Ignite Furnace", direction: "left" },
    WAIT_PUMP: { targetId: "tutorial-bellows", label: "Pump Bellows", direction: "left" }
};

const LocalSpotlight = ({ step, hasPumpedOnce }: { step: SequenceStep, hasPumpedOnce: boolean }) => {
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const animRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.getElementById(config.targetId);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) {
                setTargetRect(rect);
            }
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;

        setAnimatedRadius(2000);

        const startTime = performance.now();
        const duration = 1300;

        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);

            const nextR = 2000 - (2000 - targetR) * easeOut;
            setAnimatedRadius(nextR);

            if (progress < 1) {
                animRef.current = requestAnimationFrame(animate);
            }
        };

        animRef.current = requestAnimationFrame(animate);
        return () => { if (animRef.current !== null) cancelAnimationFrame(animRef.current); };
    }, [step, !!targetRect]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current !== null) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!config || !targetRect) return null;

    const { top, left, width, height } = targetRect;
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';

    switch (config.direction) {
        case 'top':
            pointerStyles = { left: centerX, top: top - 15, transform: 'translate(-50%, -100%)' };
            iconRotation = 'rotate(180deg)';
            animationClass = 'animate-bounce-reverse';
            containerLayout = 'flex-col-reverse';
            labelMargin = 'mb-3';
            break;
        case 'bottom':
            pointerStyles = { left: centerX, top: top + height + 15, transform: 'translateX(-50%)' };
            iconRotation = '';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
        case 'left':
            pointerStyles = { left: left - 15, top: centerY, transform: 'translate(-100%, -50%)' };
            iconRotation = 'rotate(90deg)';
            animationClass = 'animate-bounce-x-reverse';
            containerLayout = 'flex-row-reverse';
            labelMargin = 'mr-3';
            break;
        case 'right':
            pointerStyles = { left: left + width + 15, top: centerY, transform: 'translateY(-50%)' };
            iconRotation = 'rotate(-90deg)';
            animationClass = 'animate-bounce-x';
            containerLayout = 'flex-row';
            labelMargin = 'ml-3';
            break;
        default:
            pointerStyles = { left: centerX, top: top + height + 15, transform: 'translateX(-50%)' };
            iconRotation = '';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
    }

    const currentLabel = (step === 'WAIT_PUMP' && hasPumpedOnce) ? "Keep Pump!" : config.label;

    return (
        <div className="fixed inset-0 z-[3050] pointer-events-none overflow-hidden">
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs>
                    <mask id="tutorial-mask-local">
                        <rect width="100%" height="100%" fill="white" />
                        {/* Hole for the target object */}
                        <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />
                        {/* Static hole for the bottom dialogue area */}
                        <rect x="0" y="65%" width="100%" height="35%" fill="black" />
                    </mask>
                </defs>
                <rect 
                    width="100%" 
                    height="100%" 
                    fill={`rgba(0,0,0,${Math.min(0.75, 1.5 - (animatedRadius / 1000))})`} 
                    mask="url(#tutorial-mask-local)" 
                />
            </svg>

            <div className="absolute inset-0 pointer-events-none">
                <div className="absolute top-0 left-0 w-full pointer-events-auto bg-transparent" style={{ height: top }} />
                <div className="absolute left-0 w-full pointer-events-auto bg-transparent" style={{ top: top + height, bottom: 0 }} />
                <div className="absolute top-0 left-0 pointer-events-auto bg-transparent" style={{ top, height, width: left }} />
                <div className="absolute top-0 pointer-events-auto bg-transparent" style={{ top, height, left: left + width, right: 0 }} />
            </div>

            <div 
                key={`${config.targetId}-${currentLabel}`}
                className="absolute animate-in fade-in zoom-in-95 duration-300" 
                style={pointerStyles}
            >
                <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                    <Pointer className={`w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]`} style={{ transform: iconRotation.includes('rotate') ? iconRotation : undefined }} />
                    <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase tracking-widest rounded-full shadow-2xl whitespace-nowrap border-2 border-amber-400`}>
                        {currentLabel}
                    </div>
                </div>
            </div>
        </div>
    );
};

const TutorialScene: React.FC = () => {
    const { state, actions } = useGame();
    const [seq, setSeq] = useState<SequenceStep>('IDLE');
    const [currentStep, setCurrentStep] = useState(0);
    const [temp, setTemp] = useState(0); 
    const [isPumping, setIsPumping] = useState(false);
    const [hasPumpedOnce, setHasPumpedOnce] = useState(false);
    const [showFlash, setShowFlash] = useState(false);
    const [isStarted, setIsStarted] = useState(false);
    const [showSkipConfirm, setShowSkipConfirm] = useState(false);

    const mode = state.activeTutorialScene || 'PROLOGUE';

    useEffect(() => {
        if (seq === 'HEAT_CONFIRM' || seq === 'WAIT_CONTINUE_BELLOWS' || seq === 'WAIT_PUMP') {
            const timer = setInterval(() => {
                setTemp(prev => {
                    if (prev > 29.1) return prev - 0.12;
                    return prev;
                });
            }, 50);
            return () => clearInterval(timer);
        }
    }, [seq]);

    useEffect(() => {
        setHasPumpedOnce(false);
    }, [seq]);

    const bgImage = useMemo(() => {
        if (mode === 'PROLOGUE') return 'forge_ruined_bg.png';
        if (seq === 'IDLE' && !isStarted) return 'forge_ruined_bg.png';
        if (seq === 'POST_REPLACE_TALK' || seq === 'WAIT_HEAT') return 'forge_fixed_bg.png';
        if (temp >= 99.5) return 'forge_hot_bg.png';
        if (['HEAT_CONFIRM', 'WAIT_CONTINUE_BELLOWS', 'WAIT_PUMP', 'FINAL_TALK'].includes(seq)) return 'forge_start_bg.png';
        return 'forge_fixed_bg.png';
    }, [mode, seq, temp, isStarted]);

    const handleStart = () => {
        if (isStarted) return;
        if (mode === 'FURNACE_RESTORED') {
            setShowFlash(true);
            setTimeout(() => {
                setIsStarted(true);
                setSeq('POST_REPLACE_TALK');
                setCurrentStep(0);
            }, 50);
            setTimeout(() => setShowFlash(false), 800);
        } else {
            setIsStarted(true);
        }
    };

    const handleHeatUp = () => {
        if (seq !== 'WAIT_HEAT') return;
        setTemp(80);
        setSeq('HEAT_CONFIRM');
    };

    const handlePump = () => {
        setIsPumping(true);
        setHasPumpedOnce(true);
        setTemp(prev => Math.min(100, prev + 5));
        setTimeout(() => setIsPumping(false), 300);
        if (seq === 'WAIT_PUMP' && temp + 5 >= 100) {
            setSeq('FINAL_TALK');
        }
    };

    const dialogue = useMemo(() => {
        if (!isStarted) return { text: "" };
        if (mode === 'PROLOGUE') return SCRIPTS[`PROLOGUE_${currentStep}`];
        if (seq === 'POST_REPLACE_TALK') return SCRIPTS[`FURNACE_${currentStep}`];
        if (seq === 'WAIT_HEAT') return SCRIPTS.FURNACE_HEAT_PROMPT;
        if (seq === 'HEAT_CONFIRM') return SCRIPTS.FURNACE_HEATED;
        if (seq === 'WAIT_CONTINUE_BELLOWS') {
            return currentStep === 0 ? SCRIPTS.FURNACE_COOLING : SCRIPTS.FURNACE_BELLOWS_MONO;
        }
        if (seq === 'WAIT_PUMP') return SCRIPTS.FURNACE_PUMP_PROMPT;
        if (seq === 'FINAL_TALK') return SCRIPTS.FURNACE_MAXED;
        return { text: "..." };
    }, [isStarted, mode, currentStep, seq]);

    const handleNext = () => {
        if (mode === 'PROLOGUE') {
            if (currentStep < 4) setCurrentStep(prev => prev + 1);
            else actions.completePrologue();
        } else {
            if (seq === 'POST_REPLACE_TALK') {
                if (currentStep < 1) setCurrentStep(prev => prev + 1);
                else setSeq('WAIT_HEAT');
            } else if (seq === 'HEAT_CONFIRM') {
                setSeq('WAIT_CONTINUE_BELLOWS');
                setCurrentStep(0);
            } else if (seq === 'WAIT_CONTINUE_BELLOWS') {
                if (currentStep < 1) setCurrentStep(prev => prev + 1);
                else setSeq('WAIT_PUMP');
            } else if (seq === 'FINAL_TALK') {
                actions.setTutorialScene(null);
                actions.setTutorialStep('CRAFT_PROMPT');
            }
        }
    };

    const handleConfirmSkip = () => {
        actions.completeTutorial();
        setShowSkipConfirm(false);
    };

    const promptText = mode === 'FURNACE_RESTORED' ? "REPLACE FURNACE" : "TAP TO BEGIN";

    return (
        <div 
            className="fixed inset-0 z-[3000] bg-stone-950 overflow-hidden flex flex-col items-center justify-center cursor-pointer"
            onClick={handleStart}
        >
            <style>{`
                @keyframes bounce-x { 0%, 100% { transform: translateX(0); } 50% { transform: translateX(12px); } }
                .animate-bounce-x { animation: bounce-x 1s infinite; }
                @keyframes flash-out { 0% { opacity: 0; } 20% { opacity: 1; } 100% { opacity: 0; } }
                .animate-flash-out { animation: flash-out 0.8s ease-out forwards; }
            `}</style>

            <div className="absolute inset-0 z-0 pointer-events-none">
                <img src={getAssetUrl(bgImage)} className="w-full h-full object-cover opacity-80 scale-105" alt="Forge Background" />
                <div className="absolute inset-0 bg-black/30"></div>
            </div>

            <div className="absolute top-4 right-4 z-[6000] pointer-events-auto">
                <button onClick={(e) => { e.stopPropagation(); setShowSkipConfirm(true); }} className="flex items-center gap-1.5 px-4 py-2 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 text-stone-50 hover:text-stone-300 rounded-full transition-all text-[11px] font-black uppercase tracking-widest shadow-2xl backdrop-blur-md group">
                    <FastForward className="w-3.5 h-3.5 group-hover:animate-pulse" /> Skip Tutorial
                </button>
            </div>

            {showFlash && <div className="absolute inset-0 z-[4000] bg-white animate-flash-out pointer-events-none"></div>}

            {!isStarted && !showFlash && (
                <div className="relative z-20 flex flex-col items-center animate-pulse pointer-events-none">
                    <span className="text-amber-500 font-black uppercase tracking-[0.4em] text-[10px] md:text-sm drop-shadow-[0_0_15px_rgba(245,158,11,0.6)]">{promptText}</span>
                </div>
            )}

            {isStarted && mode === 'FURNACE_RESTORED' && (
                <div className="absolute top-[15dvh] right-[5vw] z-[3040] flex flex-col items-center gap-6 animate-in slide-in-from-right-8 duration-700 pointer-events-auto">
                    <div className="flex flex-col items-center">
                        <span className="text-[10px] font-black text-stone-300 uppercase tracking-tighter mb-2 font-mono drop-shadow-md">{Math.floor(20 + (temp / 100) * 1480)}°C</span>
                        <div className="w-7 h-48 md:h-64 bg-stone-950 rounded-full border-2 border-stone-800 relative shadow-2xl overflow-hidden">
                            <div className="absolute inset-1 rounded-full overflow-hidden">
                                <div className={`absolute bottom-0 left-0 right-0 rounded-full transition-all duration-300 ${temp < 30 ? 'bg-blue-600' : temp > 80 ? 'bg-red-600 animate-pulse' : 'bg-amber-500'}`} style={{ height: `${temp}%` }} />
                            </div>
                        </div>
                    </div>

                    <button id="tutorial-bellows" onClick={(e) => { e.stopPropagation(); handlePump(); }} disabled={seq !== 'WAIT_PUMP'} className={`w-16 h-16 md:w-24 md:h-24 rounded-full border-4 flex flex-col items-center justify-center transition-all shadow-2xl relative overflow-hidden group ${seq === 'WAIT_PUMP' ? 'bg-stone-800 border-amber-500 animate-pulse' : 'bg-stone-900 border-stone-800 grayscale opacity-40'} ${isPumping ? 'scale-90 brightness-150' : 'hover:scale-105'}`}>
                        <Zap className={`w-6 h-6 md:w-10 md:h-10 ${seq === 'WAIT_PUMP' ? 'text-amber-400' : 'text-stone-600'}`} />
                        <span className="text-[8px] md:text-[10px] font-black uppercase tracking-tighter mt-1">Pump</span>
                    </button>

                    <button id="tutorial-heat" onClick={(e) => { e.stopPropagation(); handleHeatUp(); }} disabled={seq !== 'WAIT_HEAT'} className={`w-14 h-14 md:w-20 md:h-20 rounded-xl border-2 flex flex-col items-center justify-center transition-all shadow-2xl ${seq === 'WAIT_HEAT' ? 'bg-orange-900/60 border-orange-500 shadow-orange-500/20' : 'bg-stone-900 border-stone-800 grayscale opacity-40'}`}>
                        <Flame className={`w-5 h-5 md:w-8 md:h-8 ${seq === 'WAIT_HEAT' ? 'text-orange-400' : 'text-stone-600'}`} />
                        <span className="text-[7px] md:text-[9px] font-black uppercase tracking-widest mt-1">Ignite</span>
                    </button>
                </div>
            )}

            {isStarted && (
                <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-[5000] pointer-events-none">
                    <DialogueBox speaker={mode === 'PROLOGUE' || seq !== 'FINAL_TALK' ? "Lockhart" : "Master Smith"} text={dialogue.text} options={['WAIT_HEAT', 'WAIT_PUMP'].includes(seq) ? [] : [{ label: "Continue", action: handleNext, variant: 'primary' }]} className="w-full relative pointer-events-auto" />
                </div>
            )}

            {isStarted && (seq === 'WAIT_HEAT' || seq === 'WAIT_PUMP') && <LocalSpotlight step={seq} hasPumpedOnce={hasPumpedOnce} />}

            <ConfirmationModal isOpen={showSkipConfirm} title="Skip Tutorial?" message="Are you sure you want to skip the introduction and go straight to the forge? All basic systems will be unlocked." confirmLabel="Skip Everything" cancelLabel="Keep Playing" onConfirm={handleConfirmSkip} onCancel={() => setShowSkipConfirm(false)} isDanger={true} />
        </div>
    );
};

export default TutorialScene;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
  X,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

/**
 * GarrickSprite: 3프레임 스프라이트 시트를 이용한 눈 깜빡임 애니메이션 컴포넌트
 */
const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); 
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000;
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      <div className="absolute bottom-[25%] left-1/2 -translate-x-1/2 w-80 h-80 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>

      <div 
        className="relative h-[75dvh] md:h-[110dvh] flex justify-center overflow-hidden bottom-[12dvh] md:bottom-0 md:translate-y-[15dvh]"
        style={{ aspectRatio: '453.3 / 1058' }}
      >
        <div 
          className="h-full w-full transition-transform duration-75 ease-linear"
          style={{
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 50px rgba(0,0,0,0.9))'
          }}
        />
      </div>

      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>
    </div>
  );
};

// Fix: Completed the MarketTab component to resolve return type errors and missing handler definitions
const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace } = state.forge;
  const currentTier = state.stats.tierLevel;

  // 튜토리얼 진행 여부 판별 (마켓 관련 단계들)
  const isTutorialActive = !!state.tutorialStep && [
    'MARKET_GUIDE', 'BROWSE_GOODS_GUIDE', 'FURNACE_GUIDE', 
    'OPEN_SHOPPING_CART', 'CLOSE_SHOPPING_CART', 'PAY_NOW', 
    'TALK_TO_GARRICK_AFTER_PURCHASE', 'LEAVE_MARKET_GUIDE'
  ].includes(state.tutorialStep);

  // 튜토리얼 단계가 FURNACE_GUIDE로 바뀌면 자동으로 CATALOG 모드로 전환
  useEffect(() => {
    if (state.tutorialStep === 'FURNACE_GUIDE') {
        setViewMode('CATALOG');
    } else if (state.tutorialStep === 'TALK_TO_GARRICK_AFTER_PURCHASE') {
        setViewMode('INTERACTION');
    }
  }, [state.tutorialStep]);

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const handleTalk = () => {
    if (state.tutorialStep === 'TALK_TO_GARRICK_AFTER_PURCHASE') {
        actions.setTutorialStep('LEAVE_MARKET_GUIDE');
        return;
    }

    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  // Fix: Added missing handleEndLongPress definition to resolve 'not found' errors
  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    longPressTimer.current = null;
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  // Fix: Added missing handlePay definition to process purchases
  const handlePay = () => {
    if (state.stats.gold < totalCost) {
      actions.showToast("Not enough gold!");
      return;
    }
    const items = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(items, totalCost);
    setCart({});
    setIsCartOpen(false);

    if (state.tutorialStep === 'PAY_NOW') {
        actions.setTutorialStep('TALK_TO_GARRICK_AFTER_PURCHASE');
    }
  };

  const filteredCatalog = useMemo(() => {
    return MARKET_CATALOG.filter(item => {
        const isOneTime = item.id === 'furnace' || item.id === 'workbench' || item.id.startsWith('scroll_');
        if (isOneTime) {
            const isOwned = (item.id === 'furnace' && state.forge.hasFurnace) || 
                            (item.id === 'workbench' && state.forge.hasWorkbench);
            if (isOwned) return false;

            // Tier based unlocks for scrolls
            if (item.id === 'scroll_t2' && state.stats.tierLevel >= 2) return false;
            if (item.id === 'scroll_t3' && state.stats.tierLevel >= 3) return false;

            // Restrict scrolls to their specific unlock tiers
            if (item.id === 'scroll_t2' && state.stats.tierLevel !== 1) return false;
            if (item.id === 'scroll_t3' && state.stats.tierLevel !== 2) return false;
        }
        return true; 
    });
  }, [state.stats.tierLevel, state.forge.hasFurnace, state.forge.hasWorkbench]);

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background Image */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('market_bg.jpeg')} 
                alt="Market" 
                className="absolute top-0 opacity-40 w-full h-full object-cover"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                }}
            />
            <div className="absolute inset-0 bg-black/20"></div>
        </div>

        {/* Garrick Sprite */}
        <div className="absolute inset-0 z-10 flex items-end justify-center pointer-events-none">
            {viewMode === 'INTERACTION' && <GarrickSprite />}
        </div>

        {/* Catalog View */}
        {viewMode === 'CATALOG' && (
            <div className="absolute inset-0 z-40 bg-stone-950/90 backdrop-blur-md p-4 md:p-8 flex flex-col animate-in fade-in duration-500">
                <div className="flex justify-between items-center mb-6">
                    <button 
                        onClick={() => {
                            if (state.tutorialStep === 'LEAVE_MARKET_GUIDE') {
                                actions.setTutorialStep(null);
                                onNavigate('FORGE');
                            } else {
                                setViewMode('INTERACTION');
                            }
                        }}
                        data-tutorial-id="MARKET_BACK_BUTTON"
                        className="flex items-center gap-2 text-stone-400 hover:text-white transition-colors"
                    >
                        <ArrowLeft className="w-5 h-5" />
                        <span className="font-black uppercase tracking-widest text-xs">Back</span>
                    </button>
                    <div className="flex items-center gap-2">
                        <Store className="w-5 h-5 text-amber-500" />
                        <h2 className="text-xl font-bold font-serif text-amber-100 uppercase tracking-tight">Garrick's Goods</h2>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4 p-2">
                    {filteredCatalog.map(item => {
                        const countInCart = cart[item.id] || 0;
                        const stock = state.marketStock[item.id] || 0;
                        const isSoldOut = stock <= 0;
                        const isMaxedInCart = countInCart >= stock;
                        const material = Object.values(MATERIALS).find(m => m.id === item.id);

                        return (
                            <div 
                                key={item.id}
                                data-tutorial-id={item.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                                className={`bg-stone-900 border-2 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all relative ${isSoldOut ? 'opacity-50 grayscale border-stone-800' : 'border-stone-800 hover:border-amber-600 shadow-xl'}`}
                            >
                                <div className="absolute top-2 right-2 flex flex-col items-end gap-1">
                                    <div className="flex items-center gap-1 bg-stone-950 px-2 py-0.5 rounded-full border border-stone-800">
                                        <Coins className="w-3 h-3 text-amber-500" />
                                        <span className="text-[10px] font-mono font-bold text-stone-300">{item.price}G</span>
                                    </div>
                                    <span className="text-[8px] font-black text-stone-600 uppercase tracking-tighter">Stock: {stock}</span>
                                </div>

                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center p-2 shadow-inner">
                                    <img src={getAssetUrl(`${item.id}.png`)} className="w-full h-full object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                    <Package className="w-8 h-8 text-stone-700 hidden" />
                                </div>

                                <div className="text-center min-w-0 w-full">
                                    <h3 className="font-bold text-stone-100 text-sm truncate uppercase">{material?.name || item.id}</h3>
                                    <p className="text-[10px] text-stone-500 truncate">{material?.description || 'Quality materials for forging.'}</p>
                                </div>

                                <div className="mt-auto w-full flex items-center gap-2">
                                    {countInCart > 0 ? (
                                        <div className="flex-1 flex items-center bg-stone-950 rounded-xl border border-amber-900/30 overflow-hidden">
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id, true)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                className="p-2 hover:bg-red-900/20 text-stone-600 hover:text-red-500 transition-colors"
                                            >
                                                <Minus className="w-4 h-4" />
                                            </button>
                                            <div className="flex-1 text-center font-mono font-black text-amber-500 text-sm">{countInCart}</div>
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                disabled={isMaxedInCart}
                                                className="p-2 hover:bg-emerald-900/20 text-stone-600 hover:text-emerald-500 transition-colors disabled:opacity-0"
                                            >
                                                <Plus className="w-4 h-4" />
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            onClick={() => addToCart(item.id)}
                                            disabled={isSoldOut}
                                            className={`w-full py-2.5 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${isSoldOut ? 'bg-stone-800 text-stone-600' : 'bg-amber-700 hover:bg-amber-600 text-white shadow-lg'}`}
                                        >
                                            {isSoldOut ? 'Out of Stock' : 'Add to Cart'}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}

        {/* Interaction Elements */}
        {viewMode === 'INTERACTION' && (
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-4 pointer-events-none">
                <div className="w-full flex justify-end px-4 pointer-events-auto">
                    <div className="flex gap-2">
                        <button 
                            onClick={handleTalk}
                            data-tutorial-id="GARRICK_TALK_BUTTON"
                            className="flex items-center gap-2 px-6 py-3 bg-stone-900/80 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl"
                        >
                            <MessageSquare className="w-4 h-4 text-amber-500" />
                            <span className="font-black text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                        </button>
                        <button 
                            onClick={() => setViewMode('CATALOG')}
                            data-tutorial-id="BROWSE_GOODS_BUTTON"
                            className="flex items-center gap-2 px-6 py-3 bg-amber-900/60 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl hover:bg-amber-800"
                        >
                            <ShoppingCart className="w-4 h-4 text-amber-100" />
                            <span className="font-black text-xs text-white uppercase tracking-widest">Trade</span>
                        </button>
                    </div>
                </div>

                <DialogueBox 
                    speaker="Garrick"
                    text={dialogue}
                    className="w-full pointer-events-auto"
                />
            </div>
        )}

        {/* Shopping Cart Bar/Modal */}
        {cartItemCount > 0 && (
            <div className={`fixed bottom-6 right-6 z-[100] transition-all duration-500 ${isCartOpen ? 'w-[320px] md:w-[400px]' : 'w-16 h-16'}`}>
                {isCartOpen ? (
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-4">
                        <div className="p-4 bg-stone-850 border-b border-stone-800 flex justify-between items-center">
                            <div className="flex items-center gap-2">
                                <ShoppingBag className="w-5 h-5 text-amber-500" />
                                <h3 className="font-bold text-amber-100 uppercase tracking-tight">Shopping Cart</h3>
                            </div>
                            <button 
                                onClick={() => {
                                    if (state.tutorialStep === 'CLOSE_SHOPPING_CART') actions.setTutorialStep('PAY_NOW');
                                    setIsCartOpen(false);
                                }}
                                data-tutorial-id="CART_TOGGLE"
                                className="p-1 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"
                            >
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="max-h-[40vh] overflow-y-auto p-4 space-y-3 custom-scrollbar">
                            {Object.entries(cart).map(([id, count]) => {
                                const item = MARKET_CATALOG.find(i => i.id === id);
                                const material = Object.values(MATERIALS).find(m => m.id === id);
                                return (
                                    <div key={id} className="flex items-center justify-between bg-stone-950 p-3 rounded-xl border border-stone-800">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-stone-900 rounded-lg flex items-center justify-center p-1.5 border border-stone-800">
                                                <img src={getAssetUrl(`${id}.png`)} className="w-full h-full object-contain" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-xs font-bold text-stone-200">{material?.name || id}</span>
                                                <span className="text-[10px] text-stone-500 font-mono">{item?.price}G x {count}</span>
                                            </div>
                                        </div>
                                        <button onClick={() => deleteFromCart(id)} className="p-2 text-stone-700 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                                    </div>
                                );
                            })}
                        </div>

                        <div className="p-4 bg-stone-950 border-t border-stone-800 space-y-4">
                            <div className="flex justify-between items-center">
                                <span className="text-stone-500 text-xs font-black uppercase tracking-widest">Total Amount</span>
                                <div className="flex items-center gap-1.5 text-amber-400 font-mono font-black text-xl">
                                    <Coins className="w-5 h-5" />
                                    {totalCost}G
                                </div>
                            </div>
                            <button 
                                onClick={handlePay}
                                data-tutorial-id="PAY_NOW_BUTTON"
                                disabled={totalCost > state.stats.gold}
                                className={`w-full py-4 rounded-xl font-black uppercase tracking-[0.2em] shadow-xl transition-all border-b-4 ${totalCost > state.stats.gold ? 'bg-stone-800 border-stone-900 text-stone-600 grayscale cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-500 border-emerald-800 text-white'}`}
                            >
                                {totalCost > state.stats.gold ? 'Insufficient Gold' : 'Pay Now'}
                            </button>
                        </div>
                    </div>
                ) : (
                    <button 
                        onClick={() => {
                            if (state.tutorialStep === 'OPEN_SHOPPING_CART') actions.setTutorialStep('CLOSE_SHOPPING_CART');
                            setIsCartOpen(true);
                        }}
                        data-tutorial-id="CART_TOGGLE"
                        className="w-16 h-16 bg-amber-600 hover:bg-amber-500 border-4 border-stone-900 text-white rounded-full flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 relative group"
                    >
                        <ShoppingCart className="w-7 h-7" />
                        <div className="absolute -top-1 -right-1 bg-red-600 text-[10px] font-black px-2 py-0.5 rounded-full border-2 border-stone-900 animate-in zoom-in">{cartItemCount}</div>
                        <div className="absolute -inset-2 rounded-full border-2 border-amber-500/20 animate-ping pointer-events-none"></div>
                    </button>
                )}
            </div>
        )}
    </div>
  );
};

// Fix: Added missing default export to fix import errors in MainGameLayout
export default MarketTab;

