import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
  X,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

/**
 * GarrickSprite: 3프레임 스프라이트 시트를 이용한 눈 깜빡임 애니메이션 컴포넌트
 */
const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); 
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000;
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      <div className="absolute bottom-[25%] left-1/2 -translate-x-1/2 w-80 h-80 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>

      <div 
        className="relative h-[75dvh] md:h-[110dvh] flex justify-center overflow-hidden bottom-[12dvh] md:bottom-0 md:translate-y-[15dvh]"
        style={{ aspectRatio: '453.3 / 1058' }}
      >
        <div 
          className="h-full w-full transition-transform duration-75 ease-linear"
          style={{
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 50px rgba(0,0,0,0.9))'
          }}
        />
      </div>

      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-64 h-10 bg-black/60 blur-3xl rounded-full -z-10"></div>
    </div>
  );
};

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [itemMultipliers, setItemMultipliers] = useState<Record<string, number>>({});

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);
  const [pressingItemId, setPressingItemId] = useState<string | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const { hasFurnace, hasWorkbench } = state.forge;
  const currentTier = state.stats.tierLevel;

  // 튜토리얼 진행 여부 판별 (마켓 관련 단계들)
  const isTutorialActive = !!state.tutorialStep && [
    'MARKET_GUIDE', 'BROWSE_GOODS_GUIDE', 'FURNACE_GUIDE', 
    'OPEN_SHOPPING_CART', 'CLOSE_SHOPPING_CART', 'PAY_NOW', 
    'TALK_TO_GARRICK_AFTER_PURCHASE', 'LEAVE_MARKET_GUIDE'
  ].includes(state.tutorialStep);

  // 튜토리얼 단계가 바뀌면 자동으로 적절한 ViewMode로 전환
  useEffect(() => {
    if (['FURNACE_GUIDE', 'OPEN_SHOPPING_CART', 'CLOSE_SHOPPING_CART', 'PAY_NOW'].includes(state.tutorialStep || '')) {
        setViewMode('CATALOG');
    } else if (['MARKET_GUIDE', 'BROWSE_GOODS_GUIDE', 'TALK_TO_GARRICK_AFTER_PURCHASE'].includes(state.tutorialStep || '')) {
        setViewMode('INTERACTION');
    }
  }, [state.tutorialStep]);

  const cartItemCount = useMemo(
    () => (Object.values(cart) as number[]).reduce((a, b) => a + b, 0),
    [cart]
  );

  const calculateTotal = () => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * (count as number) : 0);
    }, 0);
  };

  const totalCost = calculateTotal();

  const handleTalk = () => {
    // 튜토리얼 단계에 따라 대화는 TutorialOverlay에서 처리되므로 일반 대화만 셋팅
    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    const canAddCount = Math.min(amount, availableStock - currentInCart);
    if (canAddCount <= 0) return false;

    // 튜토리얼: 난로 선택 시 카트 열기 단계로 이동
    if (itemId === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      if (isOneTimeItem && nowInCart > 0) return prev;

      return {
        ...prev,
        [itemId]: nowInCart + (isOneTimeItem ? 1 : canAddCount),
      };
    });

    return true;
  };

  const removeFromCart = (itemId: string) => {
    let stillHasItems = true;
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 0) {
        stillHasItems = false;
        return prev;
      }

      const newCount = currentInCart - 1;
      const newCart = { ...prev };
      if (newCount <= 0) {
        delete newCart[itemId];
        stillHasItems = false;
      } else {
        newCart[itemId] = newCount;
      }
      return newCart;
    });
    return stillHasItems;
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const newCart = { ...prev };
      delete newCart[itemId];
      return newCart;
    });
  };

  const startContinuousAdd = (itemId: string) => {
    const success = addToCart(itemId, 1);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousAdd(itemId), currentInterval.current);
  };

  const startContinuousRemove = (itemId: string) => {
    const success = removeFromCart(itemId);
    if (!success) {
      handleEndLongPress();
      return;
    }
    currentInterval.current = Math.max(50, currentInterval.current * 0.85);
    longPressTimer.current = setTimeout(() => startContinuousRemove(itemId), currentInterval.current);
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    if (isRemove) setRemovingItemId(itemId);
    else setPressingItemId(itemId);

    currentInterval.current = 220;

    if (isRemove) {
      const success = removeFromCart(itemId);
      if (!success) {
        setRemovingItemId(null);
        return;
      }
    } else {
      const amount = itemMultipliers[itemId] || 1;
      const success = addToCart(itemId, amount);
      if (!success) {
        setPressingItemId(null);
        return;
      }
    }

    longPressTimer.current = setTimeout(() => {
      if (isRemove) startContinuousRemove(itemId);
      else startContinuousAdd(itemId);
    }, 500);
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    longPressTimer.current = null;
    setPressingItemId(null);
    setRemovingItemId(null);
  };

  const handleBuy = () => {
    if (cartItemCount === 0) {
      actions.showToast("Your cart is empty.");
      return;
    }
    if (totalCost > state.stats.gold) {
      actions.showToast("Insufficient Gold!");
      return;
    }

    const hasFurnaceInCart = !!cart['furnace'];

    // 튜토리얼: 결제 완료 후 가릭과 대화 단계로 이동
    if (state.tutorialStep === 'PAY_NOW') {
        if (hasFurnaceInCart) {
          actions.setTutorialStep('TALK_TO_GARRICK_AFTER_PURCHASE');
        } else {
          actions.setTutorialStep(null);
        }
    }

    const itemsToBuy = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(itemsToBuy, totalCost);
    setCart({});
    setIsCartOpen(false);
    actions.showToast("Purchase complete!");
  };

  const toggleCart = () => {
    if (!isCartOpen && state.tutorialStep === 'OPEN_SHOPPING_CART') {
        actions.setTutorialStep('CLOSE_SHOPPING_CART');
    } 
    else if (isCartOpen && state.tutorialStep === 'CLOSE_SHOPPING_CART') {
        actions.setTutorialStep('PAY_NOW');
    }
    setIsCartOpen(!isCartOpen);
  };

  const handleBackToForge = () => {
    if (state.tutorialStep === 'LEAVE_MARKET_GUIDE') {
      actions.setTutorialScene('FURNACE_RESTORED');
      actions.setTutorialStep(null);
    }
    onNavigate('FORGE');
  };

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background Image */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('market_bg.jpeg')} 
                alt="Market" 
                className="absolute top-0 opacity-40 w-full h-full object-cover"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                }}
            />
            <div className="absolute inset-0 bg-black/20"></div>
        </div>

        {/* Garrick Character Sprite */}
        <div className="absolute inset-0 z-10 flex items-end justify-center pointer-events-none">
            {viewMode === 'INTERACTION' && <GarrickSprite />}
        </div>

        {/* 퇴장 버튼: 튜토리얼 중이고 마지막 단계가 아니면 숨김 */}
        {(!isTutorialActive || state.tutorialStep === 'LEAVE_MARKET_GUIDE') && (
            <button 
                onClick={handleBackToForge}
                data-tutorial-id="MARKET_BACK_BUTTON"
                className={`absolute top-4 left-4 z-[1050] flex items-center gap-2 px-4 py-2 bg-stone-900/80 hover:bg-red-900/60 text-stone-300 hover:text-red-100 rounded-xl border border-stone-700 backdrop-blur-md transition-all shadow-2xl active:scale-90 group ${state.tutorialStep === 'LEAVE_MARKET_GUIDE' ? 'z-[2100] ring-4 ring-amber-400 animate-pulse' : ''}`}
                title="Leave Market"
            >
                <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
                <span className="text-xs font-black uppercase tracking-widest">Back</span>
            </button>
        )}

        {/* MODE 1: INTERACTION (Standard Dialogue) */}
        {viewMode === 'INTERACTION' && (
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-4 pointer-events-none">
                <div className="w-full flex justify-end px-4 pointer-events-auto">
                    <div className="flex gap-2">
                        <button 
                            onClick={handleTalk}
                            data-tutorial-id="GARRICK_TALK_BUTTON"
                            className={`flex items-center gap-2 px-6 py-3 bg-stone-900/80 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl active:scale-95 group ${state.tutorialStep === 'TALK_TO_GARRICK_AFTER_PURCHASE' ? 'z-[2100] ring-4 ring-amber-400 animate-pulse' : ''}`}
                        >
                            <MessageSquare className="w-4 h-4 text-amber-500" />
                            <span className="font-black text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                        </button>
                        <button 
                            onClick={() => setViewMode('CATALOG')}
                            data-tutorial-id="BROWSE_GOODS_BUTTON"
                            className={`flex items-center gap-2 px-6 py-3 bg-amber-900/60 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl hover:bg-amber-800 active:scale-95 group ${state.tutorialStep === 'BROWSE_GOODS_GUIDE' ? 'z-[2100] ring-4 ring-amber-400 animate-pulse' : ''}`}
                        >
                            <ShoppingCart className="w-4 h-4 text-amber-100" />
                            <span className="font-black text-xs text-white uppercase tracking-widest">Trade</span>
                        </button>
                    </div>
                </div>

                {!isTutorialActive && (
                    <DialogueBox 
                        speaker="Garrick"
                        text={dialogue}
                        className="w-full pointer-events-auto"
                    />
                )}
            </div>
        )}

        {/* MODE 2: CATALOG (Overlay/Grid) */}
        {viewMode === 'CATALOG' && (
            <div className="absolute inset-0 z-40 bg-stone-950/90 backdrop-blur-md p-4 md:p-8 flex flex-col animate-in fade-in duration-500">
                <div className="flex justify-between items-center mb-6">
                    <button 
                        onClick={() => !isTutorialActive && setViewMode('INTERACTION')}
                        className={`flex items-center gap-2 text-stone-400 hover:text-white transition-colors ${isTutorialActive ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <ArrowLeft className="w-5 h-5" />
                        <span className="font-black uppercase tracking-widest text-xs">Back</span>
                    </button>
                    <div className="flex items-center gap-2">
                        <Store className="w-5 h-5 text-amber-500" />
                        <h2 className="text-xl font-bold font-serif text-amber-100 uppercase tracking-tight">Garrick's Goods</h2>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4 p-2 pb-24">
                    {MARKET_CATALOG.filter(item => {
                        const isOneTime = item.id === 'furnace' || item.id === 'workbench' || item.id.startsWith('scroll_');
                        if (isOneTime) {
                            if (item.id === 'furnace' && state.forge.hasFurnace) return false;
                            if (item.id === 'workbench' && state.forge.hasWorkbench) return false;
                            if (item.id === 'scroll_t2' && state.stats.tierLevel >= 2) return false;
                            if (item.id === 'scroll_t3' && state.stats.tierLevel >= 3) return false;
                        }
                        return true;
                    }).map(item => {
                        const countInCart = cart[item.id] || 0;
                        const stock = state.marketStock[item.id] || 0;
                        const isSoldOut = stock <= 0;
                        const isMaxedInCart = countInCart >= stock;
                        const material = Object.values(MATERIALS).find(m => m.id === item.id);

                        return (
                            <div 
                                key={item.id}
                                data-tutorial-id={item.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                                className={`bg-stone-900 border-2 rounded-2xl p-4 flex flex-col items-center gap-3 transition-all relative ${isSoldOut ? 'opacity-50 grayscale border-stone-800' : 'border-stone-800 hover:border-amber-600 shadow-xl'} ${item.id === 'furnace' && state.tutorialStep === 'FURNACE_GUIDE' ? 'z-[2100] ring-4 ring-amber-400' : ''}`}
                            >
                                <div className="absolute top-2 right-2 flex flex-col items-end gap-1">
                                    <div className="flex items-center gap-1 bg-stone-950 px-2 py-0.5 rounded-full border border-stone-800">
                                        <Coins className="w-3 h-3 text-amber-500" />
                                        <span className="text-[10px] font-mono font-bold text-stone-300">{item.price}G</span>
                                    </div>
                                    <span className="text-[8px] font-black text-stone-600 uppercase tracking-tighter">Stock: {stock}</span>
                                </div>

                                <div className="w-16 h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center p-2 shadow-inner">
                                    <img src={getAssetUrl(`${item.id}.png`)} className="w-full h-full object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                    <Package className="w-8 h-8 text-stone-700 hidden" />
                                </div>

                                <div className="text-center min-w-0 w-full">
                                    <h3 className="font-bold text-stone-100 text-sm truncate uppercase">{material?.name || item.id}</h3>
                                    <p className="text-[10px] text-stone-500 truncate">{material?.description || 'Quality materials for forging.'}</p>
                                </div>

                                <div className="mt-auto w-full flex items-center gap-2">
                                    {countInCart > 0 ? (
                                        <div className="flex-1 flex items-center bg-stone-950 rounded-xl border border-amber-900/30 overflow-hidden">
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id, true)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                className="p-2 hover:bg-red-900/20 text-stone-600 hover:text-red-500 transition-colors"
                                            >
                                                <Minus className="w-4 h-4" />
                                            </button>
                                            <div className="flex-1 text-center font-mono font-black text-amber-500 text-sm">{countInCart}</div>
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                disabled={isMaxedInCart}
                                                className="p-2 hover:bg-emerald-900/20 text-stone-600 hover:text-emerald-500 transition-colors disabled:opacity-0"
                                            >
                                                <Plus className="w-4 h-4" />
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            onClick={() => addToCart(item.id)}
                                            disabled={isSoldOut}
                                            className={`w-full py-2.5 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${isSoldOut ? 'bg-stone-800 text-stone-600' : 'bg-amber-700 hover:bg-amber-600 text-white shadow-lg'}`}
                                        >
                                            {isSoldOut ? 'Out of Stock' : 'Add to Cart'}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}

        {/* Shopping Cart Bar/Toggle (Always Floating) */}
        {cartItemCount > 0 && (
            <div className={`fixed bottom-6 right-6 z-[100] transition-all duration-500 ${isCartOpen ? 'w-[320px] md:w-[400px]' : 'w-16 h-16'}`}>
                {isCartOpen ? (
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-4">
                        <div className="p-4 bg-stone-850 border-b border-stone-800 flex justify-between items-center">
                            <div className="flex items-center gap-2">
                                <ShoppingBag className="w-5 h-5 text-amber-500" />
                                <h3 className="font-bold text-amber-100 uppercase tracking-tight">Shopping Cart</h3>
                            </div>
                            <button 
                                onClick={toggleCart}
                                data-tutorial-id="CART_TOGGLE"
                                className="p-1 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"
                            >
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="max-h-[40vh] overflow-y-auto p-4 space-y-3 custom-scrollbar">
                            {Object.entries(cart).map(([id, count]) => {
                                const item = MARKET_CATALOG.find(i => i.id === id);
                                const material = Object.values(MATERIALS).find(m => m.id === id);
                                return (
                                    <div key={id} className="flex items-center justify-between bg-stone-950 p-3 rounded-xl border border-stone-800">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-stone-900 rounded-lg flex items-center justify-center p-1.5 border border-stone-800">
                                                <img src={getAssetUrl(`${id}.png`)} className="w-full h-full object-contain" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-xs font-bold text-stone-200">{material?.name || id}</span>
                                                <span className="text-[10px] text-stone-500 font-mono">{item?.price}G x {count}</span>
                                            </div>
                                        </div>
                                        <button onClick={() => deleteFromCart(id)} className="p-2 text-stone-700 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                                    </div>
                                );
                            })}
                        </div>

                        <div className="p-4 bg-stone-950 border-t border-stone-800 space-y-4">
                            <div className="flex justify-between items-center">
                                <span className="text-stone-500 text-xs font-black uppercase tracking-widest">Total Amount</span>
                                <div className="flex items-center gap-1.5 text-amber-400 font-mono font-black text-xl">
                                    <Coins className="w-5 h-5" />
                                    {totalCost}G
                                </div>
                            </div>
                            <button 
                                onClick={handleBuy}
                                data-tutorial-id="PAY_NOW_BUTTON"
                                disabled={totalCost > state.stats.gold}
                                className={`w-full py-4 rounded-xl font-black uppercase tracking-[0.2em] shadow-xl transition-all border-b-4 ${totalCost > state.stats.gold ? 'bg-stone-800 border-stone-900 text-stone-600 grayscale cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-500 border-emerald-800 text-white'} ${state.tutorialStep === 'PAY_NOW' ? 'z-[2100] ring-4 ring-amber-400' : ''}`}
                            >
                                {totalCost > state.stats.gold ? 'Insufficient Gold' : 'Pay Now'}
                            </button>
                        </div>
                    </div>
                ) : (
                    <button 
                        onClick={toggleCart}
                        data-tutorial-id="CART_TOGGLE"
                        className={`w-16 h-16 bg-amber-600 hover:bg-amber-500 border-4 border-stone-900 text-white rounded-full flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 relative group ${state.tutorialStep === 'OPEN_SHOPPING_CART' ? 'z-[2100] ring-4 ring-amber-400 animate-pulse' : ''}`}
                    >
                        <ShoppingCart className="w-7 h-7" />
                        <div className="absolute -top-1 -right-1 bg-red-600 text-[10px] font-black px-2 py-0.5 rounded-full border-2 border-stone-900 animate-in zoom-in">{cartItemCount}</div>
                        <div className="absolute -inset-2 rounded-full border-2 border-amber-500/20 animate-ping pointer-events-none"></div>
                    </button>
                )}
            </div>
        )}
    </div>
  );
};

export default MarketTab;

import React, { useState, useMemo, useRef, useEffect, useCallback } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import {
  Store,
  ShoppingCart,
  ShoppingBag,
  Coins,
  ChevronRight,
  ChevronLeft,
  Trash2,
  Plus,
  Minus,
  Package,
  MessageSquare,
  ArrowLeft,
  X,
} from 'lucide-react';
import { MATERIALS } from '../../../data/materials';
import { MARKET_CATALOG } from '../../../data/market/index';
import { getAssetUrl } from '../../../utils';

interface MarketTabProps {
  onNavigate: (tab: any) => void;
}

type MarketViewMode = 'INTERACTION' | 'CATALOG';

/**
 * GarrickSprite: 3프레임 스프라이트 시트를 이용한 눈 깜빡임 애니메이션 컴포넌트
 */
const GarrickSprite = () => {
  const [frame, setFrame] = useState(0); 
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const blink = useCallback(() => {
    setFrame(1);
    setTimeout(() => {
      setFrame(2);
      setTimeout(() => {
        setFrame(1);
        setTimeout(() => {
          setFrame(0);
          scheduleNextBlink();
        }, 80);
      }, 100);
    }, 80);
  }, []);

  const scheduleNextBlink = useCallback(() => {
    const delay = 3000 + Math.random() * 4000;
    timerRef.current = setTimeout(blink, delay);
  }, [blink]);

  useEffect(() => {
    scheduleNextBlink();
    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [scheduleNextBlink]);

  return (
    <div className="relative w-full h-full flex items-end justify-center pointer-events-none">
      {/* Glow effect behind Garrick */}
      <div className="absolute bottom-[20%] left-1/2 -translate-x-1/2 w-80 h-80 bg-amber-500/10 blur-[100px] rounded-full -z-10 animate-pulse"></div>

      {/* Garrick Body */}
      <div 
        className="relative h-[75dvh] md:h-[105dvh] flex justify-center overflow-hidden bottom-[10dvh] md:bottom-0 md:translate-y-[10dvh]"
        style={{ aspectRatio: '453.3 / 1058' }}
      >
        <div 
          className="h-full w-full transition-transform duration-75 ease-linear"
          style={{
            backgroundImage: `url(${getAssetUrl('garrick_standing_sprite.png')})`,
            backgroundSize: '300% 100%',
            backgroundPosition: `${frame * 50}% 0%`,
            imageRendering: 'pixelated',
            filter: 'drop-shadow(0 0 40px rgba(0,0,0,0.8))'
          }}
        />
      </div>

      {/* Ground Shadow */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 w-64 h-8 bg-black/60 blur-2xl rounded-full -z-10"></div>
    </div>
  );
};

const MarketTab: React.FC<MarketTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const [viewMode, setViewMode] = useState<MarketViewMode>('INTERACTION');
  const [dialogue, setDialogue] = useState("Ah, Lockhart. I heard the hammer falling on that old anvil again. Good to see you haven't given up on the family trade.");

  const [cart, setCart] = useState<Record<string, number>>({});
  const [isCartOpen, setIsCartOpen] = useState(false);

  const longPressTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const currentInterval = useRef<number>(200);

  const { hasFurnace } = state.forge;
  const { tutorialStep } = state;

  // 튜토리얼 활성화 여부
  const isTutorialActive = !!tutorialStep && [
    'MARKET_GUIDE', 'BROWSE_GOODS_GUIDE', 'FURNACE_GUIDE', 
    'OPEN_SHOPPING_CART', 'CLOSE_SHOPPING_CART', 'PAY_NOW', 
    'TALK_TO_GARRICK_AFTER_PURCHASE', 'LEAVE_MARKET_GUIDE'
  ].includes(tutorialStep);

  // 튜토리얼 단계 자동 전환 감지
  useEffect(() => {
    if (['FURNACE_GUIDE', 'OPEN_SHOPPING_CART', 'CLOSE_SHOPPING_CART', 'PAY_NOW'].includes(tutorialStep || '')) {
        setViewMode('CATALOG');
    } else if (['MARKET_GUIDE', 'BROWSE_GOODS_GUIDE', 'TALK_TO_GARRICK_AFTER_PURCHASE'].includes(tutorialStep || '')) {
        setViewMode('INTERACTION');
    }
  }, [tutorialStep]);

  const cartItemCount = useMemo(
    () => Object.values(cart).reduce((a, b) => a + b, 0),
    [cart]
  );

  const totalCost = useMemo(() => {
    return Object.entries(cart).reduce((total, [id, count]) => {
      const item = MARKET_CATALOG.find(i => i.id === id);
      return total + (item ? item.price * count : 0);
    }, 0);
  }, [cart]);

  const handleTalk = () => {
    // 튜토리얼 대화 처리
    if (tutorialStep === 'MARKET_GUIDE') {
        actions.setTutorialStep('BROWSE_GOODS_GUIDE');
        return;
    }
    if (tutorialStep === 'TALK_TO_GARRICK_AFTER_PURCHASE') {
        actions.setTutorialStep('LEAVE_MARKET_GUIDE');
        return;
    }

    const lines = [
      "The roads are getting dangerous. My suppliers are demanding hazard pay, which means my prices might sting a bit.",
      "Looking for something specific? If it's for metalwork, I've got the basics covered.",
      "I remember your grandfather. He could forge a blade that could cut through silk and stone in the same breath.",
      "The village feels quieter since the fire. But your forge... it's a sign of hope, I suppose.",
      "Don't go getting yourself killed in those ruins. I need my best customers alive and paying!",
      "If you're looking for rarer materials, you'll have to prove that forge of yours is worth the investment."
    ];
    setDialogue(lines[Math.floor(Math.random() * lines.length)]);
  };

  const addToCart = (itemId: string, amount: number = 1) => {
    const isOneTimeItem = itemId === 'furnace' || itemId === 'workbench' || itemId.startsWith('scroll_');
    const availableStock = state.marketStock[itemId] || 0;
    const currentInCart = cart[itemId] || 0;

    if (currentInCart >= availableStock) return false;

    if (itemId === 'furnace' && tutorialStep === 'FURNACE_GUIDE') {
        actions.setTutorialStep('OPEN_SHOPPING_CART');
    }

    setCart(prev => {
      const nowInCart = prev[itemId] || 0;
      if (nowInCart >= availableStock) return prev;
      return {
        ...prev,
        [itemId]: nowInCart + amount,
      };
    });
    return true;
  };

  const removeFromCart = (itemId: string) => {
    setCart(prev => {
      const currentInCart = prev[itemId] || 0;
      if (currentInCart <= 1) {
        const next = { ...prev };
        delete next[itemId];
        return next;
      }
      return { ...prev, [itemId]: currentInCart - 1 };
    });
  };

  const deleteFromCart = (itemId: string) => {
    setCart(prev => {
      const next = { ...prev };
      delete next[itemId];
      return next;
    });
  };

  const handlePay = () => {
    if (totalCost > state.stats.gold) {
      actions.showToast("Not enough gold!");
      return;
    }

    const items = Object.entries(cart).map(([id, count]) => ({ id, count }));
    actions.buyItems(items, totalCost);
    setCart({});
    setIsCartOpen(false);

    if (tutorialStep === 'PAY_NOW') {
        actions.setTutorialStep('TALK_TO_GARRICK_AFTER_PURCHASE');
    }
  };

  const handleEndLongPress = () => {
    if (longPressTimer.current) clearTimeout(longPressTimer.current);
    longPressTimer.current = null;
  };

  const handleStartLongPress = (e: React.PointerEvent, itemId: string, isRemove: boolean = false) => {
    currentInterval.current = 220;
    const action = () => {
        if (isRemove) removeFromCart(itemId);
        else addToCart(itemId);
        currentInterval.current = Math.max(50, currentInterval.current * 0.85);
        longPressTimer.current = setTimeout(action, currentInterval.current);
    };
    action();
  };

  return (
    <div className="relative h-full w-full bg-stone-950 overflow-hidden flex flex-col items-center justify-center">
        {/* Background Image Layer */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('market_bg.jpeg')} 
                alt="Market" 
                className="absolute inset-0 opacity-40 w-full h-full object-cover"
                onError={(e) => {
                    e.currentTarget.style.display = 'none';
                    e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #1c1917, #0c0a09)';
                }}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-stone-950 via-transparent to-black/40"></div>
        </div>

        {/* Garrick Sprite Layer */}
        <div className="absolute inset-0 z-10">
            {viewMode === 'INTERACTION' && <GarrickSprite />}
        </div>

        {/* --- MODE 1: INTERACTION UI --- */}
        {viewMode === 'INTERACTION' && (
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center gap-4 pointer-events-none">

                {/* Interaction Buttons - Right Aligned for Spotlight Access */}
                <div className="w-full flex justify-end px-4 pointer-events-auto">
                    <div className="flex gap-2">
                        <button 
                            onClick={handleTalk}
                            data-tutorial-id="GARRICK_TALK_BUTTON"
                            className={`flex items-center gap-2 px-6 py-3 bg-stone-900/90 border border-stone-700 hover:border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl active:scale-95 group ${tutorialStep === 'TALK_TO_GARRICK_AFTER_PURCHASE' ? 'animate-pulse' : ''}`}
                        >
                            <MessageSquare className="w-4 h-4 text-amber-500 group-hover:scale-110 transition-transform" />
                            <span className="font-black text-xs text-stone-200 uppercase tracking-widest">Talk</span>
                        </button>
                        <button 
                            onClick={() => setViewMode('CATALOG')}
                            data-tutorial-id="BROWSE_GOODS_BUTTON"
                            className={`flex items-center gap-2 px-6 py-3 bg-amber-900/80 border border-amber-500 rounded-xl backdrop-blur-md transition-all shadow-xl hover:bg-amber-800 active:scale-95 group ${tutorialStep === 'BROWSE_GOODS_GUIDE' ? 'animate-pulse' : ''}`}
                        >
                            <ShoppingCart className="w-4 h-4 text-amber-100 group-hover:scale-110 transition-transform" />
                            <span className="font-black text-xs text-white uppercase tracking-widest">Trade</span>
                        </button>
                    </div>
                </div>

                {/* Dialogue Box - Only show when not in certain tutorial steps to avoid clutter */}
                {!isTutorialActive && (
                    <DialogueBox 
                        speaker="Garrick"
                        text={dialogue}
                        className="w-full pointer-events-auto"
                    />
                )}
            </div>
        )}

        {/* --- MODE 2: CATALOG UI --- */}
        {viewMode === 'CATALOG' && (
            <div className="absolute inset-0 z-40 bg-stone-950/95 backdrop-blur-xl p-4 md:p-8 flex flex-col animate-in fade-in duration-500">
                <div className="flex justify-between items-center mb-6">
                    <button 
                        onClick={() => !isTutorialActive && setViewMode('INTERACTION')}
                        className={`flex items-center gap-2 text-stone-400 hover:text-white transition-colors ${isTutorialActive ? 'opacity-30 cursor-not-allowed' : ''}`}
                    >
                        <ArrowLeft className="w-5 h-5" />
                        <span className="font-black uppercase tracking-widest text-xs">Back</span>
                    </button>
                    <div className="flex items-center gap-2">
                        <Store className="w-5 h-5 text-amber-500" />
                        <h2 className="text-xl font-bold font-serif text-amber-100 uppercase tracking-tight">Garrick's Goods</h2>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3 md:gap-4 p-2 pb-32">
                    {MARKET_CATALOG.filter(item => {
                        const isOneTime = item.id === 'furnace' || item.id === 'workbench' || item.id.startsWith('scroll_');
                        if (isOneTime) {
                            if (item.id === 'furnace' && state.forge.hasFurnace) return false;
                            if (item.id === 'workbench' && state.forge.hasWorkbench) return false;
                            if (item.id === 'scroll_t2' && state.stats.tierLevel >= 2) return false;
                            if (item.id === 'scroll_t3' && state.stats.tierLevel >= 3) return false;
                        }
                        return true;
                    }).map(item => {
                        const countInCart = cart[item.id] || 0;
                        const stock = state.marketStock[item.id] || 0;
                        const isSoldOut = stock <= 0;
                        const isMaxedInCart = countInCart >= stock;
                        const material = Object.values(MATERIALS).find(m => m.id === item.id);

                        return (
                            <div 
                                key={item.id}
                                data-tutorial-id={item.id === 'furnace' ? 'FURNACE_ITEM' : undefined}
                                className={`bg-stone-900 border-2 rounded-2xl p-4 flex flex-col items-center gap-2 transition-all relative ${isSoldOut ? 'opacity-50 grayscale border-stone-800' : 'border-stone-800 hover:border-amber-600 shadow-xl'}`}
                            >
                                <div className="absolute top-2 right-2 flex flex-col items-end gap-1">
                                    <div className="flex items-center gap-1 bg-stone-950 px-2 py-0.5 rounded-full border border-stone-800">
                                        <Coins className="w-3 h-3 text-amber-500" />
                                        <span className="text-[10px] font-mono font-bold text-stone-300">{item.price}G</span>
                                    </div>
                                    <span className="text-[8px] font-black text-stone-600 uppercase tracking-tighter">In Stock: {stock}</span>
                                </div>

                                <div className="w-14 h-14 md:w-16 md:h-16 bg-stone-950 rounded-xl border border-stone-800 flex items-center justify-center p-2 shadow-inner group-hover:scale-105 transition-transform">
                                    <img src={getAssetUrl(`${item.id}.png`)} className="w-full h-full object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                    <Package className="w-8 h-8 text-stone-700 hidden" />
                                </div>

                                <div className="text-center min-w-0 w-full mb-1">
                                    <h3 className="font-bold text-stone-100 text-xs truncate uppercase tracking-tight">{material?.name || item.id}</h3>
                                    <p className="text-[9px] text-stone-500 truncate">{material?.description || 'Quality materials for forging.'}</p>
                                </div>

                                <div className="mt-auto w-full">
                                    {countInCart > 0 ? (
                                        <div className="flex items-center bg-stone-950 rounded-xl border border-amber-900/30 overflow-hidden h-9">
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id, true)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                className="px-2 h-full hover:bg-red-900/20 text-stone-600 hover:text-red-500 transition-colors"
                                            >
                                                <Minus className="w-3.5 h-3.5" />
                                            </button>
                                            <div className="flex-1 text-center font-mono font-black text-amber-500 text-xs">{countInCart}</div>
                                            <button 
                                                onPointerDown={(e) => handleStartLongPress(e, item.id)}
                                                onPointerUp={handleEndLongPress}
                                                onPointerLeave={handleEndLongPress}
                                                disabled={isMaxedInCart}
                                                className="px-2 h-full hover:bg-emerald-900/20 text-stone-600 hover:text-emerald-500 transition-colors disabled:opacity-0"
                                            >
                                                <Plus className="w-3.5 h-3.5" />
                                            </button>
                                        </div>
                                    ) : (
                                        <button 
                                            onClick={() => addToCart(item.id)}
                                            disabled={isSoldOut}
                                            className={`w-full py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${isSoldOut ? 'bg-stone-800 text-stone-600' : 'bg-amber-700 hover:bg-amber-600 text-white shadow-lg'}`}
                                        >
                                            {isSoldOut ? 'Sold Out' : 'Purchase'}
                                        </button>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        )}

        {/* Global Exit Button for Tutorial Extraction */}
        {tutorialStep === 'LEAVE_MARKET_GUIDE' && (
            <div className="absolute top-4 left-4 z-[100] animate-in fade-in zoom-in duration-500">
                <button 
                    onClick={() => {
                        actions.setTutorialScene('FURNACE_RESTORED');
                        actions.setTutorialStep(null);
                        onNavigate('FORGE');
                    }}
                    data-tutorial-id="MARKET_BACK_BUTTON"
                    className="flex items-center gap-2 px-6 py-3 bg-red-900/80 border-2 border-red-500 rounded-xl text-white shadow-2xl animate-pulse"
                >
                    <ArrowLeft className="w-5 h-5" />
                    <span className="font-black uppercase tracking-widest text-sm">Return to Forge</span>
                </button>
            </div>
        )}

        {/* Shopping Cart Widget */}
        {cartItemCount > 0 && (
            <div className={`fixed bottom-6 right-6 z-[100] transition-all duration-500 ${isCartOpen ? 'w-[320px] md:w-[400px]' : 'w-16 h-16'}`}>
                {isCartOpen ? (
                    <div className="bg-stone-900 border-2 border-amber-600/50 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 slide-in-from-bottom-4 h-full max-h-[70vh]">
                        <div className="p-4 bg-stone-850 border-b border-stone-800 flex justify-between items-center">
                            <div className="flex items-center gap-2">
                                <ShoppingBag className="w-5 h-5 text-amber-500" />
                                <h3 className="font-bold text-amber-100 uppercase tracking-tight">Shopping Cart</h3>
                            </div>
                            <button 
                                onClick={() => {
                                    if (tutorialStep === 'CLOSE_SHOPPING_CART') actions.setTutorialStep('PAY_NOW');
                                    setIsCartOpen(false);
                                }}
                                className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"
                            >
                                <X className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                            {Object.entries(cart).map(([id, count]) => {
                                const item = MARKET_CATALOG.find(i => i.id === id);
                                const material = Object.values(MATERIALS).find(m => m.id === id);
                                return (
                                    <div key={id} className="flex items-center justify-between bg-stone-950 p-3 rounded-xl border border-stone-800">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-stone-900 rounded-lg flex items-center justify-center p-1.5 border border-stone-800">
                                                <img src={getAssetUrl(`${id}.png`)} className="w-full h-full object-contain" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-xs font-bold text-stone-200">{material?.name || id}</span>
                                                <span className="text-[10px] text-stone-500 font-mono">{item?.price}G x {count}</span>
                                            </div>
                                        </div>
                                        <button onClick={() => deleteFromCart(id)} className="p-2 text-stone-700 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                                    </div>
                                );
                            })}
                        </div>

                        <div className="p-4 bg-stone-950 border-t border-stone-800 space-y-4">
                            <div className="flex justify-between items-center">
                                <span className="text-stone-500 text-xs font-black uppercase tracking-widest">Total Amount</span>
                                <div className="flex items-center gap-1.5 text-amber-400 font-mono font-black text-xl">
                                    <Coins className="w-5 h-5" />
                                    {totalCost}G
                                </div>
                            </div>
                            <button 
                                onClick={handlePay}
                                data-tutorial-id="PAY_NOW_BUTTON"
                                disabled={totalCost > state.stats.gold}
                                className={`w-full py-4 rounded-xl font-black uppercase tracking-[0.2em] shadow-xl transition-all border-b-4 ${totalCost > state.stats.gold ? 'bg-stone-800 border-stone-900 text-stone-600 grayscale cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-500 border-emerald-800 text-white'} ${tutorialStep === 'PAY_NOW' ? 'animate-pulse' : ''}`}
                            >
                                {totalCost > state.stats.gold ? 'Insufficient Gold' : 'Secure Purchase'}
                            </button>
                        </div>
                    </div>
                ) : (
                    <button 
                        onClick={() => {
                            if (tutorialStep === 'OPEN_SHOPPING_CART') actions.setTutorialStep('CLOSE_SHOPPING_CART');
                            setIsCartOpen(true);
                        }}
                        data-tutorial-id="CART_TOGGLE"
                        className={`w-16 h-16 bg-amber-600 hover:bg-amber-500 border-4 border-stone-900 text-white rounded-full flex items-center justify-center shadow-2xl transition-all hover:scale-110 active:scale-90 relative group ${tutorialStep === 'OPEN_SHOPPING_CART' ? 'animate-pulse ring-4 ring-amber-400' : ''}`}
                    >
                        <ShoppingCart className="w-7 h-7" />
                        <div className="absolute -top-1 -right-1 bg-red-600 text-[10px] font-black px-2 py-0.5 rounded-full border-2 border-stone-900 animate-in zoom-in">{cartItemCount}</div>
                        <div className="absolute -inset-2 rounded-full border-2 border-amber-500/20 animate-ping pointer-events-none"></div>
                    </button>
                )}
            </div>
        )}
    </div>
  );
};

export default MarketTab;
